interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

function assertInRange(value: number, min: number, max: number, ctx: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in "${ctx}"`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n  |  start/n  |  start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepRaw] = segment.split("/");
    const step = parseInt(stepRaw, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step "${stepRaw}" in "${segment}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      [start, end] = rangePart.split("-").map(Number);
    } else {
      start = parseInt(rangePart, 10);
      end = max;
    }

    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid step expression "${segment}"`);
    }
    assertInRange(start, min, max, segment);
    assertInRange(end,   min, max, segment);

    const values: number[] = [];
    for (let v = start; v <= end; v += step) values.push(v);
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startRaw, endRaw] = segment.split("-");
    const start = parseInt(startRaw, 10);
    const end   = parseInt(endRaw,   10);
    if (isNaN(start) || isNaN(end)) throw new SyntaxError(`Invalid range "${segment}"`);
    assertInRange(start, min, max, segment);
    assertInRange(end,   min, max, segment);
    if (start > end) throw new RangeError(`Range start > end in "${segment}"`);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new SyntaxError(`Unrecognised field value "${segment}"`);
  assertInRange(value, min, max, segment);
  return [value];
}

function parseField(field: string, min: number, max: number): number[] {
  const segments = field.split(",");
  const merged = segments.flatMap(s => parseSegment(s.trim(), min, max));
  return [...new Set(merged)].sort((a, b) => a - b);
}

function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteF, hourF, domF, monthF, dowF] = parts;

  return {
    minute:     parseField(minuteF, FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max),
    hour:       parseField(hourF,   FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max),
    dayOfMonth: parseField(domF,    FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max),
    month:      parseField(monthF,  FIELD_RANGES.month.min,      FIELD_RANGES.month.max),
    dayOfWeek:  parseField(dowF,    FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max),
  };
}

export default parseCron;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 6 },   // dayOfWeek
];

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, config: FieldConfig): number[] {
  const { min, max } = config;

  if (field === "*") return range(min, max);

  if (field.includes(",")) {
    const values = field.split(",").flatMap(part => parseField(part.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = endStr !== undefined ? parseInt(endStr, 10) : max;
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in: ${field}`);
    if (start < min || end > max) throw new Error(`Value out of range in: ${field}`);
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${field}`);
    if (start < min || end > max || start > end) throw new Error(`Range out of bounds: ${field}`);
    return range(start, end);
  }

  const value = parseInt(field, 10);
  if (isNaN(value)) throw new Error(`Invalid value: ${field}`);
  if (value < min || value > max) throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  return [value];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minute, hour, dayOfMonth, month, dayOfWeek] = fields.map((field, i) =>
    parseField(field, FIELD_CONFIGS[i])
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new Error("maxTokens must be positive");
    if (options.refillRate <= 0) throw new Error("refillRate must be positive");
    if (options.refillIntervalMs <= 0) throw new Error("refillIntervalMs must be positive");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new Error("tokens must be positive");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new Error("tokens must be positive");
    if (tokens > this.maxTokens) throw new Error("tokens exceeds maxTokens capacity");

    while (!this.tryConsume(tokens)) {
      this.refill();
      const tokensNeeded = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
      const elapsed = Date.now() - this.lastRefillTime;
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs - elapsed);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type Scalar = string | number | boolean | null | undefined;
type NestedRecord = { [key: string]: NestedRecord | Scalar | unknown[] };

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, Scalar | unknown[]> = {},
  seen = new WeakSet<object>()
): Record<string, Scalar | unknown[]> {
  if (seen.has(obj)) {
    throw new Error(`Circular reference detected at key: "${prefix}"`);
  }
  seen.add(obj);

  for (const key of Object.keys(obj)) {
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = obj[key];

    const isPlainObject =
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.getPrototypeOf(value) === Object.prototype;

    if (isPlainObject && Object.keys(value as object).length > 0) {
      flattenObject(value as Record<string, unknown>, fullKey, result, seen);
    } else {
      result[fullKey] = value as Scalar | unknown[];
    }
  }

  seen.delete(obj);
  return result;
}

export default flattenObject;

