type Scalar = string | number | boolean | null | undefined;
type FlatResult = Record<string, Scalar | unknown[]>;

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  seen = new WeakSet<object>()
): FlatResult {
  const result: FlatResult = {};

  if (seen.has(obj)) {
    if (prefix) result[prefix] = "[Circular]";
    return result;
  }
  seen.add(obj);

  const entries = Object.entries(obj);

  if (entries.length === 0) {
    // preserve empty object as a leaf
    if (prefix) result[prefix] = obj as unknown as Scalar;
  } else {
    for (const [key, value] of entries) {
      const dotKey = prefix ? `${prefix}.${key}` : key;

      const isPlainObject =
        value !== null &&
        typeof value === "object" &&
        !Array.isArray(value) &&
        Object.getPrototypeOf(value) === Object.prototype;

      if (isPlainObject) {
        Object.assign(
          result,
          flattenObject(value as Record<string, unknown>, dotKey, seen)
        );
      } else {
        result[dotKey] = value as Scalar | unknown[];
      }
    }
  }

  seen.delete(obj);
  return result;
}

