export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new Error("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new Error("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new Error("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new Error("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new Error("tokens must be > 0");
    if (tokens > this.maxTokens) throw new Error("tokens exceeds maxTokens capacity");

    while (!this.tryConsume(tokens)) {
      this.refill();
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const waitMs = Math.max(
        1,
        intervalsNeeded * this.refillIntervalMs -
          (Date.now() - this.lastRefillTime) % this.refillIntervalMs
      );
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{
    tokens: number;
    resolve: () => void;
    reject: (error: Error) => void;
  }>;
  private nextDrainHandle: ReturnType<typeof setTimeout> | null;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.nextDrainHandle = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    // Ignore non-positive elapsed to handle same-tick calls and backwards clock drift.
    if (elapsed > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime = now;
    }
  }

  private msUntilAvailable(tokens: number): number {
    if (this.currentTokens >= tokens) return 0;
    const deficit = tokens - this.currentTokens;
    // Ceil so we always overshoot slightly rather than wake up too early.
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private scheduleNextDrain(): void {
    if (this.waitQueue.length === 0) return;

    // Cancel any stale pending drain — conditions may have changed (e.g. reset).
    if (this.nextDrainHandle !== null) {
      clearTimeout(this.nextDrainHandle);
    }

    const delay = this.msUntilAvailable(this.waitQueue[0].tokens);

    this.nextDrainHandle = setTimeout(() => {
      this.nextDrainHandle = null;
      this.drainQueue();
    }, delay);
  }

  private drainQueue(): void {
    this.applyRefill();

    // Service waiters in strict FIFO order to prevent starvation of large requests.
    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];
      if (this.currentTokens >= waiter.tokens) {
        this.waitQueue.shift();
        this.currentTokens -= waiter.tokens;
        waiter.resolve();
      } else {
        // The head can't be satisfied yet — don't skip ahead to smaller requests.
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextDrain();
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a non-negative finite number, got ${tokens}`);
    }
    // Zero-token consume is always allowed; requesting more than the bucket can
    // ever hold is permanently impossible — fail fast rather than implying retry.
    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Cancel any pending drain before drainQueue potentially reschedules.
    if (this.nextDrainHandle !== null) {
      clearTimeout(this.nextDrainHandle);
      this.nextDrainHandle = null;
    }
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError(`tokens must be a non-negative finite number, got ${tokens}`)
      );
    }
    if (tokens === 0) return Promise.resolve();
    // A request that can never be satisfied must be rejected, not queued forever.
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }

    this.applyRefill();

    // Only bypass the queue if it is empty — preserves FIFO ordering for fairness.
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextDrain();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  readonly tokens: number;
  readonly resolve: () => void;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly queue: Waiter[];
  private drainTimer: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got: ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got: ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got: ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.queue = [];
    this.drainTimer = null;
  }

  /**
   * Lazily adds tokens proportional to elapsed time.
   * Always advances lastRefillTime — handles backward clock drift gracefully
   * by treating negative elapsed as zero rather than freezing the reference.
   */
  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    this.lastRefillTime = now;
    if (elapsed > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + (elapsed / this.refillIntervalMs) * this.refillRate
      );
    }
  }

  /**
   * Attempts to immediately consume `tokens` (default 1).
   * Returns `true` if the tokens were available and consumed; `false` otherwise.
   * Note: succeeds even if there are pending waiters — for non-queued semantics,
   * callers that mix tryConsume and waitForTokens must coordinate externally.
   */
  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a non-negative finite number, got: ${tokens}`);
    }
    if (tokens === 0) return true;
    // A request that can never be satisfied even at full capacity is always denied.
    if (tokens > this.maxTokens) return false;

    this.refill();
    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  /** Returns the current available token count after a lazy refill. */
  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  /**
   * Resets the bucket to full capacity, cancels any pending drain timer, and
   * immediately processes the waiters queue so no waiter sleeps longer than needed.
   */
  reset(): void {
    if (this.drainTimer !== null) {
      clearTimeout(this.drainTimer);
      this.drainTimer = null;
    }
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  /**
   * Waits until `tokens` (default 1) are available, then consumes them.
   * Resolves in strict FIFO order to prevent starvation.
   * Rejects immediately if `tokens` exceeds `maxTokens` — the bucket could
   * never accumulate that many tokens, so waiting would hang forever.
   */
  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError(`tokens must be a non-negative finite number, got: ${tokens}`)
      );
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; ` +
          `this request can never be fulfilled`
        )
      );
    }

    return new Promise<void>((resolve) => {
      this.refill();

      // Fast path: serve immediately only when nobody is ahead in line.
      // Skipping this guard would let late callers steal tokens from earlier waiters.
      if (this.queue.length === 0 && this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        resolve();
        return;
      }

      this.queue.push({ tokens, resolve });
      this.scheduleDrain();
    });
  }

  /**
   * Drains the queue in FIFO order for as long as the bucket can satisfy the
   * front waiter. Calling resolve() only schedules a microtask — it does NOT
   * execute synchronously — so the while loop sees a stable queue snapshot and
   * cannot recurse into itself.
   */
  private drainQueue(): void {
    this.refill();
    while (this.queue.length > 0) {
      const waiter = this.queue[0]!;
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.queue.shift();
        waiter.resolve();
      } else {
        break;
      }
    }
    if (this.queue.length > 0) {
      this.scheduleDrain();
    }
  }

  /**
   * Schedules exactly one setTimeout to wake up when the front waiter's tokens
   * should be available. The delay is computed from current token deficit and
   * the configured fill rate, rounded up to the nearest millisecond so the timer
   * fires no earlier than needed (avoiding a busy-reschedule loop).
   *
   * If a timer is already pending, this is a no-op — the existing timer will
   * call drainQueue, which will reschedule if it still cannot serve the queue.
   */
  private scheduleDrain(): void {
    if (this.drainTimer !== null || this.queue.length === 0) return;

    const tokensNeeded = this.queue[0]!.tokens - this.currentTokens;
    const delayMs =
      tokensNeeded <= 0
        ? 0
        : Math.ceil((tokensNeeded / this.refillRate) * this.refillIntervalMs);

    this.drainTimer = setTimeout(() => {
      this.drainTimer = null;
      this.drainQueue();
    }, delayMs);
  }
}

export default RateLimiter;

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be greater than 0");
    }
    if (options.refillRate <= 0) {
      throw new RangeError("refillRate must be greater than 0");
    }
    if (options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be greater than 0");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyLazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) {
      return;
    }

    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + tokensToAdd
      );
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    if (tokens === 0) {
      return true;
    }
    if (tokens > this.maxTokens) {
      return false;
    }

    this.applyLazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyLazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    if (tokens === 0) {
      return;
    }
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested tokens (${tokens}) exceed maximum bucket capacity (${this.maxTokens})`
      );
    }

    while (true) {
      this.applyLazyRefill();

      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return;
      }

      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const msUntilRefill =
        this.refillIntervalMs -
        (Date.now() - this.lastRefillTime) % this.refillIntervalMs;
      const waitMs =
        (intervalsNeeded - 1) * this.refillIntervalMs + msUntilRefill;

      await new Promise<void>((resolve) =>
        setTimeout(resolve, Math.max(0, waitMs))
      );
    }
  }
}

export default RateLimiter;

export class RateLimiter {
