export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private processing: boolean;
  private wakeUp: (() => void) | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a finite non-negative number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.processing = false;
    this.wakeUp = null;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    this.lastRefillTime = now;

    if (elapsed > 0 && this.refillRate > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    }
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.wakeUp?.();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens === 0) return;
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); can never be fulfilled`
      );
    }

    await new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      void this.drainQueue();
    });
  }

  private async drainQueue(): Promise<void> {
    if (this.processing || this.waitQueue.length === 0) return;
    this.processing = true;

    try {
      while (this.waitQueue.length > 0) {
        const head = this.waitQueue[0];
        this.refill();

        if (this.currentTokens >= head.tokens) {
          this.currentTokens -= head.tokens;
          this.waitQueue.shift();
          head.resolve();
          continue;
        }

        const deficit = head.tokens - this.currentTokens;
        const delayMs =
          this.refillRate > 0
            ? Math.ceil((deficit / this.refillRate) * this.refillIntervalMs)
            : 2_147_483_647; // refillRate is 0; stall until reset() fires wakeUp

        await this.pause(delayMs);
      }
    } finally {
      this.processing = false;
    }

    // A new item may have been enqueued while we were resolving the last one
    if (this.waitQueue.length > 0) {
      void this.drainQueue();
    }
  }

  private pause(ms: number): Promise<void> {
    return new Promise<void>((resolve) => {
      const timer = setTimeout(() => {
        this.wakeUp = null;
        resolve();
      }, ms);

      // Allows reset() to interrupt an in-progress sleep
      this.wakeUp = () => {
        clearTimeout(timer);
        this.wakeUp = null;
        resolve();
      };
    });
  }
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES: Record<keyof CronExpression, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function parseNaturalNumber(s: string, context: string): number {
  if (!/^\d+$/.test(s)) {
    throw new Error(`Expected a non-negative integer but got "${s}" in "${context}"`);
  }
  const n = parseInt(s, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Value "${s}" exceeds safe integer bounds in "${context}"`);
  }
  return n;
}

function assertInRange(n: number, { min, max }: FieldRange, context: string): void {
  if (n < min || n > max) {
    throw new RangeError(
      `Value ${n} is outside the valid range [${min}, ${max}] in "${context}"`
    );
  }
}

function buildSequence(start: number, end: number, step: number, context: string): number[] {
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got ${step} in "${context}"`);
  }
  if (start > end) {
    throw new Error(
      `Range start (${start}) must not exceed range end (${end}) in "${context}"`
    );
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseToken(token: string, range: FieldRange): number[] {
  // ── Step expressions: "*/N", "N/N", or "N-N/N" ───────────────────────────
  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const rangePart = token.slice(0, slashIdx);
    const stepPart  = token.slice(slashIdx + 1);

    if (stepPart.includes("/")) {
      throw new Error(`Multiple "/" separators in token "${token}"`);
    }

    const step = parseNaturalNumber(stepPart, token);
    if (step === 0) {
      throw new Error(`Step value must not be zero in "${token}"`);
    }

    // "*/step"
    if (rangePart === "*") {
      return buildSequence(range.min, range.max, step, token);
    }

    // "N-M/step"
    if (rangePart.includes("-")) {
      const dashIdx  = rangePart.indexOf("-");
      const startStr = rangePart.slice(0, dashIdx);
      const endStr   = rangePart.slice(dashIdx + 1);
      if (!startStr || endStr.includes("-")) {
        throw new Error(`Invalid range part "${rangePart}" in "${token}"`);
      }
      const start = parseNaturalNumber(startStr, token);
      const end   = parseNaturalNumber(endStr,   token);
      assertInRange(start, range, token);
      assertInRange(end,   range, token);
      return buildSequence(start, end, step, token);
    }

    // "N/step" — walk from N to field max
    const start = parseNaturalNumber(rangePart, token);
    assertInRange(start, range, token);
    return buildSequence(start, range.max, step, token);
  }

  // ── Wildcard ──────────────────────────────────────────────────────────────
  if (token === "*") {
    return buildSequence(range.min, range.max, 1, token);
  }

  // ── Range: "N-M" ──────────────────────────────────────────────────────────
  if (token.includes("-")) {
    const dashIdx  = token.indexOf("-");
    const startStr = token.slice(0, dashIdx);
    const endStr   = token.slice(dashIdx + 1);
    if (!startStr || endStr.includes("-")) {
      throw new Error(`Invalid range "${token}"`);
    }
    const start = parseNaturalNumber(startStr, token);
    const end   = parseNaturalNumber(endStr,   token);
    assertInRange(start, range, token);
    assertInRange(end,   range, token);
    return buildSequence(start, end, 1, token);
  }

  // ── Single numeric value ──────────────────────────────────────────────────
  const value = parseNaturalNumber(token, token);
  assertInRange(value, range, token);
  return [value];
}

function parseField(raw: string, range: FieldRange, name: string): number[] {
  const trimmed = raw.trim();
  if (!trimmed) {
    throw new Error(`Cron field "${name}" must not be empty`);
  }

  const tokens = trimmed.split(",");
  const seen   = new Set<number>();

  for (const token of tokens) {
    const t = token.trim();
    if (!t) {
      throw new Error(`Empty segment in cron field "${name}": "${raw}"`);
    }
    for (const v of parseToken(t, range)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new Error("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression requires exactly 5 space-separated fields, got ${parts.length}: "${expression}"`
    );
  }

  return {
    minute:     parseField(parts[0], FIELD_RANGES.minute,     "minute"),
    hour:       parseField(parts[1], FIELD_RANGES.hour,       "hour"),
    dayOfMonth: parseField(parts[2], FIELD_RANGES.dayOfMonth, "dayOfMonth"),
    month:      parseField(parts[3], FIELD_RANGES.month,      "month"),
    dayOfWeek:  parseField(parts[4], FIELD_RANGES.dayOfWeek,  "dayOfWeek"),
  };
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: Record<string, unknown>,
  prefix = "",
  ancestors = new WeakSet<object>()
): Record<string, unknown> {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject requires a plain object; received ${
        input === null ? "null" : typeof input
      }`
    );
  }

  if (ancestors.has(input)) {
    throw new TypeError(
      `Circular reference detected${prefix ? ` at path "${prefix}"` : ""}`
    );
  }

  ancestors.add(input);
  const result: Record<string, unknown> = {};

  for (const key of Object.keys(input)) {
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = input[key];

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      // Recurse only into non-empty plain objects; everything else is a leaf.
      // Arrays, Dates, Maps, RegExps, null, primitives → stored as-is.
      const nested = flattenObject(value, fullKey, ancestors);
      for (const nestedKey of Object.keys(nested)) {
        result[nestedKey] = nested[nestedKey];
      }
    } else {
      result[fullKey] = value;
    }
  }

  // Remove from ancestors on the way back up so shared (non-circular)
  // references in sibling branches are handled correctly.
  ancestors.delete(input);

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;
type FlatObject = Record<string, unknown>;

function isTraversable(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !(value instanceof Date) &&
    !(value instanceof RegExp) &&
    !(value instanceof Function)
  );
}

function flatten(
  obj: PlainObject,
  prefix: string,
  result: FlatObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key "${prefix.replace(/\.$/, "")}"`
    );
  }

  ancestors.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0 && prefix !== "") {
    // Preserve empty objects/arrays as leaf values
    result[prefix.slice(0, -1)] = obj;
  } else {
    for (const key of keys) {
      const value = obj[key];
      const fullKey = `${prefix}${key}`;

      if (isTraversable(value)) {
        const nested = value as PlainObject;
        const nestedKeys = Object.keys(nested);

        if (nestedKeys.length === 0) {
          result[fullKey] = value;
        } else {
          flatten(nested, `${fullKey}.`, result, ancestors);
        }
      } else {
        result[fullKey] = value;
      }
    }
  }

  ancestors.delete(obj);
}

export default function flattenObject(obj: PlainObject): FlatObject {
  if (obj === null || typeof obj !== "object") {
    throw new TypeError(`Expected a plain object, received ${obj === null ? "null" : typeof obj}`);
  }

  const result: FlatObject = {};
  flatten(obj, "", result, new WeakSet());
  return result;
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldBounds {
  readonly min: number;
  readonly max: number;
}

const FIELD_BOUNDS: Readonly<Record<keyof CronExpression, FieldBounds>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
} as const;

function parseNonNegativeInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Expected non-negative integer in ${context}, got: "${raw}"`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer value out of safe bounds in ${context}: "${raw}"`);
  }
  return n;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  const trimmed = segment.trim();
  if (trimmed.length === 0) {
    throw new Error('Empty segment encountered in cron field');
  }

  const slashCount = (trimmed.match(/\//g) ?? []).length;
  if (slashCount > 1) {
    throw new Error(`Multiple step operators in segment: "${trimmed}"`);
  }

  let rangeStr: string;
  let step: number | undefined;

  if (slashCount === 1) {
    const slashIdx = trimmed.indexOf('/');
    rangeStr = trimmed.slice(0, slashIdx);
    const stepStr = trimmed.slice(slashIdx + 1);
    step = parseNonNegativeInt(stepStr, `step of "${trimmed}"`);
    if (step === 0) {
      throw new Error(`Step value cannot be zero in segment: "${trimmed}"`);
    }
  } else {
    rangeStr = trimmed;
  }

  let rangeStart: number;
  let rangeEnd: number;

  if (rangeStr === '*') {
    rangeStart = min;
    rangeEnd = max;
  } else {
    const dashIdx = rangeStr.indexOf('-');
    if (dashIdx === -1) {
      const n = parseNonNegativeInt(rangeStr, `value in "${trimmed}"`);
      rangeStart = n;
      rangeEnd = step !== undefined ? max : n;
    } else {
      if (rangeStr.indexOf('-', dashIdx + 1) !== -1) {
        throw new Error(`Invalid range expression: "${rangeStr}"`);
      }
      const startStr = rangeStr.slice(0, dashIdx);
      const endStr = rangeStr.slice(dashIdx + 1);
      if (startStr.length === 0 || endStr.length === 0) {
        throw new Error(`Malformed range expression: "${rangeStr}"`);
      }
      rangeStart = parseNonNegativeInt(startStr, `range start in "${trimmed}"`);
      rangeEnd   = parseNonNegativeInt(endStr,   `range end in "${trimmed}"`);
    }
  }

  if (rangeStart < min || rangeStart > max) {
    throw new RangeError(`Value ${rangeStart} out of valid range [${min}, ${max}]`);
  }
  if (rangeEnd < min || rangeEnd > max) {
    throw new RangeError(`Value ${rangeEnd} out of valid range [${min}, ${max}]`);
  }
  if (rangeStart > rangeEnd) {
    throw new RangeError(`Range start ${rangeStart} exceeds end ${rangeEnd}`);
  }

  const effectiveStep = step ?? 1;
  const values: number[] = [];
  for (let i = rangeStart; i <= rangeEnd; i += effectiveStep) {
    values.push(i);
  }
  return values;
}

function parseField(field: string, min: number, max: number): number[] {
  const segments = field.split(',');
  if (segments.some((s) => s.trim().length === 0)) {
    throw new Error(`Empty segment in field: "${field}"`);
  }

  const seen = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment, min, max)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== 'string') {
    throw new TypeError(`Expected string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error('Cron expression cannot be empty');
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${trimmed}"`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = parts;

  return {
    minute:     parseField(minuteStr, FIELD_BOUNDS.minute.min,     FIELD_BOUNDS.minute.max),
    hour:       parseField(hourStr,   FIELD_BOUNDS.hour.min,       FIELD_BOUNDS.hour.max),
    dayOfMonth: parseField(domStr,    FIELD_BOUNDS.dayOfMonth.min, FIELD_BOUNDS.dayOfMonth.max),
    month:      parseField(monthStr,  FIELD_BOUNDS.month.min,      FIELD_BOUNDS.month.max),
    dayOfWeek:  parseField(dowStr,    FIELD_BOUNDS.dayOfWeek.min,  FIELD_BOUNDS.dayOfWeek.max),
  };
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (error: Error) => void;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private scheduledTimer: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(
        `maxTokens must be a positive finite number, got ${maxTokens}`
      );
    }
    if (!Number.isFinite(refillRate) || refillRate < 0) {
      throw new RangeError(
        `refillRate must be a non-negative finite number, got ${refillRate}`
      );
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs < 0) {
      throw new RangeError(
        `refillIntervalMs must be a non-negative finite number, got ${refillIntervalMs}`
      );
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledTimer = null;
  }

  private lazyRefill(): void {
    // Guard: no refill if rate or interval is zero (avoids divide-by-zero and NaN drift)
    if (this.refillRate <= 0 || this.refillIntervalMs <= 0) return;

    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime = now;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(
        `tokens must be a positive finite number, got ${tokens}`
      );
    }

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    // Cancel any pending wake-up; we will drive the queue immediately below
    if (this.scheduledTimer !== null) {
      clearTimeout(this.scheduledTimer);
      this.scheduledTimer = null;
    }

    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      return Promise.reject(
        new RangeError(`tokens must be a positive finite number, got ${tokens}`)
      );
    }

    // A request larger than the bucket's capacity can never be satisfied
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); ` +
            `this request can never be satisfied`
        )
      );
    }

    this.lazyRefill();

    // Fast path: satisfy immediately only when no one is ahead of us (FIFO fairness)
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextWake();
    });
  }

  // ---------------------------------------------------------------------------
  // Private helpers
  // ---------------------------------------------------------------------------

  /** Drain the front of the queue for as long as we can cover each request. */
  private drainQueue(): void {
    this.lazyRefill();

    while (this.waitQueue.length > 0) {
      const front = this.waitQueue[0];

      if (this.currentTokens >= front.tokens) {
        this.currentTokens -= front.tokens;
        this.waitQueue.shift();
        front.resolve(); // Schedules the Promise micro-task; does not re-enter here
      } else {
        break; // Cannot satisfy the head; nothing further can be satisfied either
      }
    }

    // Re-arm the timer for whatever is still waiting
    if (this.waitQueue.length > 0) {
      this.scheduleNextWake();
    }
  }

  /** Schedule a single wake-up timer sized to when the next waiter can be served. */
  private scheduleNextWake(): void {
    // Only one timer at a time; it will re-arm itself via drainQueue if needed
    if (this.scheduledTimer !== null || this.waitQueue.length === 0) return;

    const front = this.waitQueue[0];
    const deficit = front.tokens - this.currentTokens;

    // Deficit already covered (e.g. concurrent call consumed and returned tokens)
    if (deficit <= 0) {
      this.scheduledTimer = setTimeout(() => {
        this.scheduledTimer = null;
        this.drainQueue();
      }, 0);
      return;
    }

    // No refill is possible — waiter will remain pending indefinitely.
    // This is a degenerate configuration; nothing useful to schedule.
    if (this.refillRate <= 0 || this.refillIntervalMs <= 0) return;

    const msPerToken = this.refillIntervalMs / this.refillRate;
    // Use Math.ceil so we don't wake up a hair early and spin unnecessarily
    const delay = Math.max(1, Math.ceil(deficit * msPerToken));

    this.scheduledTimer = setTimeout(() => {
      this.scheduledTimer = null;
      this.drainQueue();
    }, delay);
  }
}

export default RateLimiter;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (
      !Number.isFinite(options.maxTokens) ||
      options.maxTokens <= 0 ||
      !Number.isInteger(options.maxTokens)
    ) {
      throw new RangeError(`maxTokens must be a positive integer, got: ${options.maxTokens}`);
    }
    if (
      !Number.isFinite(options.refillRate) ||
      options.refillRate <= 0 ||
      !Number.isInteger(options.refillRate)
    ) {
      throw new RangeError(`refillRate must be a positive integer, got: ${options.refillRate}`);
    }
    if (
      !Number.isFinite(options.refillIntervalMs) ||
      options.refillIntervalMs <= 0 ||
      !Number.isInteger(options.refillIntervalMs)
    ) {
      throw new RangeError(
        `refillIntervalMs must be a positive integer, got: ${options.refillIntervalMs}`
      );
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyLazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0 || !Number.isInteger(tokens)) {
      throw new RangeError(`tokens must be a positive integer, got: ${tokens}`);
    }
    if (tokens > this.maxTokens) {
      return false;
    }

    this.applyLazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyLazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0 || !Number.isInteger(tokens)) {
      throw new RangeError(`tokens must be a positive integer, got: ${tokens}`);
    }
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds maxTokens capacity of ${this.maxTokens}`
      );
    }

    while (true) {
      if (this.tryConsume(tokens)) {
        return;
      }

      this.applyLazyRefill();

      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const msUntilRefill =
        this.refillIntervalMs - (Date.now() - this.lastRefillTime) % this.refillIntervalMs;
      const waitMs = (intervalsNeeded - 1) * this.refillIntervalMs + msUntilRefill;

      await new Promise<void>((resolve) => setTimeout(resolve, Math.max(0, waitMs)));
    }
  }
}

export default RateLimiter;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 },
];

function assertDigits(s: string, context: string): void {
  if (!/^\d+$/.test(s)) {
    throw new Error(`Invalid non-integer token "${s}" in ${context}`);
  }
}

function parseSegment(
  segment: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const values: number[] = [];

  if (segment === "") {
    throw new Error(`Empty segment in field "${fieldName}"`);
  }

  // Step expression: base/step  (e.g. "*/15", "1-30/5", "2/10")
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new Error(
        `Invalid step expression "${segment}" in field "${fieldName}": only one "/" allowed`
      );
    }
    const [base, stepStr] = slashParts;

    assertDigits(stepStr, `step of "${segment}" in field "${fieldName}"`);
    const step = parseInt(stepStr, 10);
    if (step <= 0) {
      throw new Error(
        `Step value must be >= 1, got "${stepStr}" in field "${fieldName}"`
      );
    }

    let rangeStart = min;
    let rangeEnd = max;

    if (base === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (base.includes("-")) {
      const dashParts = base.split("-");
      if (dashParts.length !== 2) {
        throw new Error(
          `Invalid range "${base}" in step expression for field "${fieldName}"`
        );
      }
      assertDigits(dashParts[0], `range start in "${segment}" for field "${fieldName}"`);
      assertDigits(dashParts[1], `range end in "${segment}" for field "${fieldName}"`);
      rangeStart = parseInt(dashParts[0], 10);
      rangeEnd = parseInt(dashParts[1], 10);
    } else {
      assertDigits(base, `step base "${base}" in field "${fieldName}"`);
      rangeStart = parseInt(base, 10);
      rangeEnd = max;
    }

    if (rangeStart < min || rangeStart > max) {
      throw new Error(
        `Range start ${rangeStart} is out of bounds [${min}, ${max}] for field "${fieldName}"`
      );
    }
    if (rangeEnd < min || rangeEnd > max) {
      throw new Error(
        `Range end ${rangeEnd} is out of bounds [${min}, ${max}] for field "${fieldName}"`
      );
    }
    if (rangeStart > rangeEnd) {
      throw new Error(
        `Range start ${rangeStart} exceeds end ${rangeEnd} in field "${fieldName}"`
      );
    }

    for (let v = rangeStart; v <= rangeEnd; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    for (let v = min; v <= max; v++) {
      values.push(v);
    }
    return values;
  }

  // Range: "1-5"
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new Error(
        `Invalid range "${segment}" in field "${fieldName}": only one "-" allowed`
      );
    }
    assertDigits(dashParts[0], `range start in "${segment}" for field "${fieldName}"`);
    assertDigits(dashParts[1], `range end in "${segment}" for field "${fieldName}"`);
    const start = parseInt(dashParts[0], 10);
    const end = parseInt(dashParts[1], 10);

    if (start < min || start > max) {
      throw new Error(
        `Range start ${start} is out of bounds [${min}, ${max}] for field "${fieldName}"`
      );
    }
    if (end < min || end > max) {
      throw new Error(
        `Range end ${end} is out of bounds [${min}, ${max}] for field "${fieldName}"`
      );
    }
    if (start > end) {
      throw new Error(
        `Range start ${start} exceeds end ${end} in field "${fieldName}"`
      );
    }

    for (let v = start; v <= end; v++) {
      values.push(v);
    }
    return values;
  }

  // Single integer
  assertDigits(segment, `value in field "${fieldName}"`);
  const num = parseInt(segment, 10);
  if (num < min || num > max) {
    throw new Error(
      `Value ${num} is out of bounds [${min}, ${max}] for field "${fieldName}"`
    );
  }
  values.push(num);
  return values;
}

function parseField(
  field: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  if (typeof field !== "string" || field.length === 0) {
    throw new Error(`Field "${fieldName}" must be a non-empty string`);
  }

  const segments = field.split(",");
  if (segments.some((s) => s === "")) {
    throw new Error(
      `Field "${fieldName}" contains an empty segment (check for leading/trailing/consecutive commas)`
    );
  }

  const seen = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), min, max, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;
  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseField(fields[i], min, max, name);
  }

  return result;
}

interface WaiterEntry {
  tokens: number;
  resolve: () => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: WaiterEntry[] = [];
  private drainTimer: ReturnType<typeof setTimeout> | null = null;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate < 0) {
      throw new RangeError(`refillRate must be a non-negative finite number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  // Lazy refill: advances by whole completed intervals, preserving sub-interval remainder.
  private refill(): void {
    if (this.refillRate === 0) return;

    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate,
      );
      // Advance by completed intervals only, keeping partial interval in the next window.
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a non-negative finite number, got ${tokens}`);
    }
    if (tokens === 0) return true;
    // A request larger than maxTokens can never be satisfied, even on a full bucket.
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  reset(): void {
    if (this.drainTimer !== null) {
      clearTimeout(this.drainTimer);
      this.drainTimer = null;
    }
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainWaiters();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a non-negative finite number, got ${tokens}`);
    }
    if (tokens === 0) return;
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; ` +
          `this request can never be fulfilled`,
      );
    }

    this.refill();

    // Fast path: no one ahead of us and tokens are available right now.
    if (this.waiters.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return;
    }

    // Slow path: enqueue and wait. FIFO ordering prevents starvation of large requests.
    return new Promise<void>((resolve) => {
      this.waiters.push({ tokens, resolve });
      // Only the first enqueue needs to kick off the drain cycle.
      if (this.waiters.length === 1) {
        this.scheduleDrain();
      }
    });
  }

  // Returns milliseconds until `tokensNeeded` can be served given the current state.
  // Caller must have already called refill().
  private msUntilTokens(tokensNeeded: number): number {
    if (this.currentTokens >= tokensNeeded) return 0;
    if (this.refillRate === 0) return Infinity;

    const deficit = tokensNeeded - this.currentTokens;
    const intervalsNeeded = Math.ceil(deficit / this.refillRate);
    const elapsed = Date.now() - this.lastRefillTime;

    // Floor to at least 1ms to avoid degenerate zero-delay tight loops
    // if a timer fires fractionally early.
    return Math.max(1, intervalsNeeded * this.refillIntervalMs - elapsed);
  }

  private scheduleDrain(): void {
    if (this.drainTimer !== null || this.waiters.length === 0) return;

    const wait = this.msUntilTokens(this.waiters[0].tokens);
    if (wait === Infinity) {
      // refillRate is 0; waiters are permanently blocked until reset() is called.
      return;
    }

    this.drainTimer = setTimeout(() => {
      this.drainTimer = null;
      this.drainWaiters();
    }, wait);
  }

  private drainWaiters(): void {
    this.refill();

    const toResolve: Array<() => void> = [];

    while (this.waiters.length > 0) {
      const head = this.waiters[0];
      // Strict FIFO: the head must be satisfiable before anyone behind it is served.
      if (this.currentTokens >= head.tokens) {
        this.currentTokens -= head.tokens;
        this.waiters.shift();
        toResolve.push(head.resolve);
      } else {
        break;
      }
    }

    // Re-arm the timer before calling resolve() to reduce re-entrancy surface:
    // if a resolve callback synchronously calls waitForTokens(), scheduleDrain()
    // will be a no-op because drainTimer is already set.
    if (this.waiters.length > 0) {
      this.scheduleDrain();
    }

    for (const resolve of toResolve) {
      resolve();
    }
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES: Readonly<Record<FieldName, FieldRange>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: readonly FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (!Number.isInteger(value) || value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${range.min}–${range.max}] in "${context}"`
    );
  }
}

function expandToken(token: string, range: FieldRange): number[] {
  const { min, max } = range;

  // */N — wildcard with step
  const wildcardStep = token.match(/^\*\/(\d+)$/);
  if (wildcardStep) {
    const step = parseInt(wildcardStep[1], 10);
    if (step < 1) throw new RangeError(`Step must be ≥ 1 in "${token}"`);
    const values: number[] = [];
    for (let i = min; i <= max; i += step) values.push(i);
    return values;
  }

  // * — full wildcard
  if (token === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) values.push(i);
    return values;
  }

  // A-B/N — range with step
  const rangeStep = token.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (rangeStep) {
    const start = parseInt(rangeStep[1], 10);
    const end   = parseInt(rangeStep[2], 10);
    const step  = parseInt(rangeStep[3], 10);
    if (step < 1) throw new RangeError(`Step must be ≥ 1 in "${token}"`);
    assertInRange(start, range, token);
    assertInRange(end,   range, token);
    if (start > end) throw new RangeError(`Range start exceeds end in "${token}"`);
    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // A-B — range
  const rangePart = token.match(/^(\d+)-(\d+)$/);
  if (rangePart) {
    const start = parseInt(rangePart[1], 10);
    const end   = parseInt(rangePart[2], 10);
    assertInRange(start, range, token);
    assertInRange(end,   range, token);
    if (start > end) throw new RangeError(`Range start exceeds end in "${token}"`);
    const values: number[] = [];
    for (let i = start; i <= end; i++) values.push(i);
    return values;
  }

  // A/N — anchored step (start at A, step to max)
  const valueStep = token.match(/^(\d+)\/(\d+)$/);
  if (valueStep) {
    const start = parseInt(valueStep[1], 10);
    const step  = parseInt(valueStep[2], 10);
    if (step < 1) throw new RangeError(`Step must be ≥ 1 in "${token}"`);
    assertInRange(start, range, token);
    const values: number[] = [];
    for (let i = start; i <= max; i += step) values.push(i);
    return values;
  }

  // A — single integer value
  if (/^\d+$/.test(token)) {
    const num = parseInt(token, 10);
    assertInRange(num, range, token);
    return [num];
  }

  throw new SyntaxError(`Invalid cron field token: "${token}"`);
}

function parseField(expression: string, range: FieldRange): number[] {
  const parts = expression.split(",");
  if (parts.length === 0) throw new SyntaxError(`Empty field expression`);

  const seen = new Set<number>();
  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed.length === 0) {
      throw new SyntaxError(`Empty segment in field expression: "${expression}"`);
    }
    for (const v of expandToken(trimmed, range)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    result[name] = parseField(fields[i], FIELD_RANGES[name]);
  }
  return result;
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof CronExpression;

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function rangeArray(start: number, end: number, step = 1): number[] {
  if (step <= 0) throw new Error(`Step must be positive, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) result.push(i);
  return result;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`${context}: ${value} is outside valid range [${min}, ${max}]`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const left = segment.slice(0, slashIdx);
    const stepStr = segment.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || stepStr.trim() === "") {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }
    if (step <= 0) throw new RangeError(`Step must be positive: ${step}`);

    if (left === "*") {
      return rangeArray(min, max, step);
    }

    if (left.includes("-")) {
      const [startStr, endStr] = left.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in step: "${left}"`);
      assertInRange(start, min, max, "Range start");
      assertInRange(end, min, max, "Range end");
      if (start > end) throw new RangeError(`Range start ${start} > end ${end}`);
      return rangeArray(start, end, step);
    }

    const start = parseInt(left, 10);
    if (isNaN(start)) throw new Error(`Invalid step expression: "${segment}"`);
    assertInRange(start, min, max, "Step base");
    return rangeArray(start, max, step);
  }

  // Wildcard
  if (segment === "*") return rangeArray(min, max);

  // Range: a-b
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const startStr = segment.slice(0, dashIdx);
    const endStr = segment.slice(dashIdx + 1);
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${segment}"`);
    assertInRange(start, min, max, "Range start");
    assertInRange(end, min, max, "Range end");
    if (start > end) throw new RangeError(`Range start ${start} > end ${end}`);
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value) || segment.trim() === "") {
    throw new Error(`Invalid cron field token: "${segment}"`);
  }
  assertInRange(value, min, max, "Value");
  return [value];
}

function parseField(raw: string, min: number, max: number): number[] {
  const parts = raw.split(",");
  if (parts.length === 0) throw new Error(`Empty cron field`);

  const seen = new Set<number>();
  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") throw new Error(`Empty token in comma list: "${raw}"`);
    for (const v of parseSegment(trimmed, min, max)) seen.add(v);
  }

  return [...seen].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max),
    hour:       parseField(hourRaw,   FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max),
    dayOfMonth: parseField(domRaw,    FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max),
    month:      parseField(monthRaw,  FIELD_RANGES.month.min,      FIELD_RANGES.month.max),
    dayOfWeek:  parseField(dowRaw,    FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined) {
    return result;
  }

  if (typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) {
      result[prefix] = obj as Primitive | unknown[];
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = {} as unknown as Primitive;
    }
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    const sanitizedKey = String(key);
    if (sanitizedKey.length === 0) {
      continue;
    }

    const fullKey = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.getPrototypeOf(value) === Object.prototype
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) {
      result[prefix] = obj as Primitive | Array<unknown>;
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = obj as unknown as Primitive;
    }
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const sanitizedKey = String(key);
    const newKey = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_META = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  },
] as const;

function range(from: number, to: number, step = 1): number[] {
  if (step <= 0) throw new Error(`Step must be positive, got ${step}`);
  if (from > to) throw new Error(`Range start ${from} exceeds end ${to}`);
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  const slashIdx = segment.indexOf("/");

  if (slashIdx !== -1) {
    const left = segment.slice(0, slashIdx);
    const step = parseInt(segment.slice(slashIdx + 1), 10);
    if (!Number.isFinite(step) || step <= 0)
      throw new Error(`Invalid step in "${segment}"`);

    if (left === "*") return range(min, max, step);

    const dashIdx = left.indexOf("-");
    if (dashIdx !== -1) {
      const start = parseInt(left.slice(0, dashIdx), 10);
      const end   = parseInt(left.slice(dashIdx + 1), 10);
      if (!Number.isFinite(start) || !Number.isFinite(end))
        throw new Error(`Invalid range in "${segment}"`);
      return range(start, end, step);
    }

    const start = parseInt(left, 10);
    if (!Number.isFinite(start))
      throw new Error(`Invalid start value in "${segment}"`);
    return range(start, max, step);
  }

  if (segment === "*") return range(min, max);

  const dashIdx = segment.indexOf("-");
  if (dashIdx !== -1) {
    const start = parseInt(segment.slice(0, dashIdx), 10);
    const end   = parseInt(segment.slice(dashIdx + 1), 10);
    if (!Number.isFinite(start) || !Number.isFinite(end))
      throw new Error(`Invalid range "${segment}"`);
    return range(start, end);
  }

  const value = parseInt(segment, 10);
  if (!Number.isFinite(value))
    throw new Error(`Invalid value "${segment}"`);
  return [value];
}

function parseField(field: string, name: string, min: number, max: number): number[] {
  const seen = new Set<number>();

  for (const part of field.split(",")) {
    const trimmed = part.trim();
    if (!trimmed) throw new Error(`Empty segment in field "${name}"`);

    for (const v of parseSegment(trimmed, min, max)) {
      if (v < min || v > max)
        throw new Error(
          `Value ${v} out of valid range [${min}, ${max}] for field "${name}"`
        );
      seen.add(v);
    }
  }

  if (seen.size === 0)
    throw new Error(`Field "${name}" produced no values`);

  return [...seen].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5)
    throw new Error(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;
  const [minuteMeta, hourMeta, domMeta, monthMeta, dowMeta] = FIELD_META;

  return {
    minute:     parseField(minuteRaw, minuteMeta.name, minuteMeta.min, minuteMeta.max),
    hour:       parseField(hourRaw,   hourMeta.name,   hourMeta.min,   hourMeta.max),
    dayOfMonth: parseField(domRaw,    domMeta.name,    domMeta.min,    domMeta.max),
    month:      parseField(monthRaw,  monthMeta.name,  monthMeta.min,  monthMeta.max),
    dayOfWeek:  parseField(dowRaw,    dowMeta.name,    dowMeta.min,    dowMeta.max),
  };
}

export type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type Bounds = { min: number; max: number };

function parseIntStrict(s: string, context: string): number {
  if (!/^\d+$/.test(s)) {
    throw new Error(`Expected an integer, got "${s}" in "${context}"`);
  }
  return parseInt(s, 10);
}

function assertInBounds(value: number, bounds: Bounds, context: string): void {
  if (value < bounds.min || value > bounds.max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${bounds.min}, ${bounds.max}] in "${context}"`
    );
  }
}

function parseSegment(segment: string, bounds: Bounds): number[] {
  if (segment.includes('/')) {
    const slashParts = segment.split('/');
    if (slashParts.length !== 2) {
      throw new Error(`Invalid step expression: "${segment}"`);
    }
    const [rangeExpr, stepStr] = slashParts;
    const step = parseIntStrict(stepStr, segment);
    if (step === 0) {
      throw new Error(`Step value cannot be zero in "${segment}"`);
    }

    let start: number;
    let end: number;

    if (rangeExpr === '*') {
      start = bounds.min;
      end = bounds.max;
    } else if (rangeExpr.includes('-')) {
      const dashParts = rangeExpr.split('-');
      if (dashParts.length !== 2) {
        throw new Error(`Invalid range in step expression: "${rangeExpr}"`);
      }
      start = parseIntStrict(dashParts[0], segment);
      end = parseIntStrict(dashParts[1], segment);
    } else {
      start = parseIntStrict(rangeExpr, segment);
      end = bounds.max;
    }

    assertInBounds(start, bounds, segment);
    assertInBounds(end, bounds, segment);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in "${segment}"`);
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  if (segment.includes('-')) {
    const dashParts = segment.split('-');
    if (dashParts.length !== 2) {
      throw new Error(`Invalid range expression: "${segment}"`);
    }
    const start = parseIntStrict(dashParts[0], segment);
    const end = parseIntStrict(dashParts[1], segment);
    assertInBounds(start, bounds, segment);
    assertInBounds(end, bounds, segment);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in "${segment}"`);
    }
    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  if (segment === '*') {
    const values: number[] = [];
    for (let i = bounds.min; i <= bounds.max; i++) {
      values.push(i);
    }
    return values;
  }

  const value = parseIntStrict(segment, segment);
  assertInBounds(value, bounds, segment);
  return [value];
}

function parseField(expr: string, bounds: Bounds): number[] {
  if (!expr) {
    throw new Error('Empty cron field expression');
  }

  const valueSet = new Set<number>();
  for (const segment of expr.split(',')) {
    if (!segment) {
      throw new Error(`Empty segment in cron expression field: "${expr}"`);
    }
    for (const v of parseSegment(segment, bounds)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

function parseCron(expression: string): ParsedCron {
  if (typeof expression !== 'string') {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new Error('Cron expression cannot be empty');
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, { min: 0, max: 59 }),
    hour:       parseField(hourExpr,   { min: 0, max: 23 }),
    dayOfMonth: parseField(domExpr,    { min: 1, max: 31 }),
    month:      parseField(monthExpr,  { min: 1, max: 12 }),
    dayOfWeek:  parseField(dowExpr,    { min: 0, max: 6  }),
  };
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, flatKey, result);
    } else {
      result[flatKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type CronField = {
  values: number[];
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof ParsedCron, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function generateRange(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseField(token: string, min: number, max: number): number[] {
  const allValues = generateRange(min, max);

  if (token === "*") {
    return allValues;
  }

  if (token.startsWith("*/")) {
    const step = parseInt(token.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${token}`);
    return generateRange(min, max, step);
  }

  if (token.includes(",")) {
    const parts = token.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), min, max)) {
        values.add(v);
      }
    }
    return [...values].sort((a, b) => a - b);
  }

  if (token.includes("-")) {
    const [rawStart, rawEnd, rawStep] = token.includes("/")
      ? (() => {
          const [range, step] = token.split("/");
          const [s, e] = range.split("-");
          return [s, e, step];
        })()
      : [...token.split("-"), undefined];

    const start = parseInt(rawStart, 10);
    const end = parseInt(rawEnd!, 10);
    const step = rawStep !== undefined ? parseInt(rawStep, 10) : 1;

    if (isNaN(start) || isNaN(end) || isNaN(step)) {
      throw new Error(`Invalid range: ${token}`);
    }
    if (start < min || end > max || start > end) {
      throw new Error(`Range out of bounds: ${token} (allowed ${min}-${max})`);
    }

    return generateRange(start, end, step);
  }

  const num = parseInt(token, 10);
  if (isNaN(num)) throw new Error(`Invalid cron value: ${token}`);
  if (num < min || num > max) {
    throw new Error(`Value ${num} out of range (${min}-${max})`);
  }
  return [num];
}

export function parseCron(expression: string): ParsedCron {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Invalid cron expression: expected 5 fields, got ${parts.length}`);
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof ParsedCron)[];
  const result = {} as ParsedCron;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(parts[i], min, max);
  }

  return result;
}

export default parseCron;

type CronField = {
  values: number[];
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof ParsedCron, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clampAndValidate(value: number, min: number, max: number, fieldName: string): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${fieldName}"`);
  }
  return value;
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Step with wildcard: */step
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step <= 0) throw new RangeError(`Step value must be positive in field "${fieldName}"`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) {
      result.push(i);
    }
    return result;
  }

  // Range with optional step: start-end or start-end/step
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const start = clampAndValidate(parseInt(rangeMatch[1], 10), min, max, fieldName);
    const end = clampAndValidate(parseInt(rangeMatch[2], 10), min, max, fieldName);
    if (start > end) throw new RangeError(`Range start ${start} > end ${end} in field "${fieldName}"`);
    const step = rangeMatch[3] ? parseInt(rangeMatch[3], 10) : 1;
    if (step <= 0) throw new RangeError(`Step value must be positive in field "${fieldName}"`);
    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return result;
  }

  // Step with start: start/step
  const stepStartMatch = segment.match(/^(\d+)\/(\d+)$/);
  if (stepStartMatch) {
    const start = clampAndValidate(parseInt(stepStartMatch[1], 10), min, max, fieldName);
    const step = parseInt(stepStartMatch[2], 10);
    if (step <= 0) throw new RangeError(`Step value must be positive in field "${fieldName}"`);
    const result: number[] = [];
    for (let i = start; i <= max; i += step) {
      result.push(i);
    }
    return result;
  }

  // Single number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    // Normalize dayOfWeek: 7 is treated as 0 (Sunday)
    const normalized = fieldName === "dayOfWeek" && value === 7 ? 0 : value;
    clampAndValidate(normalized, min, max, fieldName);
    return [normalized];
  }

  throw new SyntaxError(`Invalid cron segment "${segment}" in field "${fieldName}"`);
}

function parseField(field: string, min: number, max: number, fieldName: string): number[] {
  const segments = field.split(",");
  const values = new Set<number>();
  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), min, max, fieldName);
    for (const v of parsed) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof ParsedCron)[];
  const result = {} as ParsedCron;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const { min, max } = FIELD_RANGES[name];
    result[name] = parseField(parts[i], min, max, name);
  }

  return result;
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

function validateBounds(
  start: number,
  end: number,
  min: number,
  max: number,
  raw: string
): void {
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end} in "${raw}"`);
  }
  if (start < min || end > max) {
    throw new Error(`Range [${start}-${end}] out of bounds [${min}-${max}] in "${raw}"`);
  }
}

function parseField(field: string, min: number, max: number): number[] {
  const trimmed = field.trim();

  // Comma-separated list — split and recurse, then deduplicate and sort
  if (trimmed.includes(",")) {
    const values = trimmed
      .split(",")
      .flatMap((part) => parseField(part, min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step expression: `*/<n>` or `<start>-<end>/<n>` or `<start>/<n>`
  if (trimmed.includes("/")) {
    const slashIdx = trimmed.lastIndexOf("/");
    const rangePart = trimmed.slice(0, slashIdx);
    const step = parseInt(trimmed.slice(slashIdx + 1), 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in "${trimmed}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      const dashIdx = rangePart.indexOf("-");
      rangeMin = parseInt(rangePart.slice(0, dashIdx), 10);
      rangeMax = parseInt(rangePart.slice(dashIdx + 1), 10);
      if (isNaN(rangeMin) || isNaN(rangeMax)) {
        throw new Error(`Invalid range in step expression "${trimmed}"`);
      }
      validateBounds(rangeMin, rangeMax, min, max, trimmed);
    } else {
      rangeMin = parseInt(rangePart, 10);
      if (isNaN(rangeMin) || rangeMin < min || rangeMin > max) {
        throw new Error(`Invalid start value in step expression "${trimmed}"`);
      }
      rangeMax = max;
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard: all values in range
  if (trimmed === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Range: `<start>-<end>`
  if (trimmed.includes("-")) {
    const dashIdx = trimmed.indexOf("-");
    const start = parseInt(trimmed.slice(0, dashIdx), 10);
    const end = parseInt(trimmed.slice(dashIdx + 1), 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range "${trimmed}"`);
    }
    validateBounds(start, end, min, max, trimmed);

    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single numeric value
  const value = parseInt(trimmed, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value "${trimmed}"`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  }
  return [value];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const fieldNames: FieldName[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];

  return fieldNames.reduce((acc, name, i) => {
    const { min, max } = FIELD_RANGES[name];
    acc[name] = parseField(fields[i], min, max);
    return acc;
  }, {} as CronExpression);
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be greater than 0");
    }
    if (options.refillRate <= 0) {
      throw new RangeError("refillRate must be greater than 0");
    }
    if (options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be greater than 0");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) {
      throw new RangeError("tokens must be greater than 0");
    }
    if (tokens > this.maxTokens) {
      return false;
    }

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) {
      throw new RangeError("tokens must be greater than 0");
    }
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens}) and can never be satisfied`,
      );
    }

    while (true) {
      this.refill();

      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return;
      }

      const deficit = tokens - this.currentTokens;
      const waitMs = Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);

      await new Promise<void>((resolve) => setTimeout(resolve, Math.max(1, waitMs)));
    }
  }
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

class RateLimiter {
  private readonly _maxTokens: number;
  private readonly _refillRate: number;
  private readonly _refillIntervalMs: number;

  private _tokens: number;
  private _lastRefillTime: number;
  private readonly _queue: Waiter[];
  private _timer: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate < 0) {
      throw new RangeError(`refillRate must be a non-negative finite number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`);
    }

    this._maxTokens = maxTokens;
    this._refillRate = refillRate;
    this._refillIntervalMs = refillIntervalMs;
    this._tokens = maxTokens;
    this._lastRefillTime = Date.now();
    this._queue = [];
    this._timer = null;
  }

  private _applyRefill(): void {
    if (this._refillRate === 0) return;

    const now = Date.now();
    const elapsed = now - this._lastRefillTime;
    if (elapsed < this._refillIntervalMs) return;

    const intervals = Math.floor(elapsed / this._refillIntervalMs);
    this._tokens = Math.min(this._maxTokens, this._tokens + intervals * this._refillRate);
    this._lastRefillTime += intervals * this._refillIntervalMs;
  }

  private _msUntilAvailable(needed: number): number {
    const deficit = needed - this._tokens;
    if (deficit <= 0) return 0;
    if (this._refillRate === 0) return Infinity;

    const intervalsNeeded = Math.ceil(deficit / this._refillRate);
    const msSinceLastRefill = Date.now() - this._lastRefillTime;
    return Math.max(0, intervalsNeeded * this._refillIntervalMs - msSinceLastRefill);
  }

  // Iterative (not recursive) to avoid stack overflow on large reject runs
  private _scheduleNext(): void {
    while (true) {
      if (this._timer !== null || this._queue.length === 0) return;

      this._applyRefill();
      const head = this._queue[0];
      const delay = this._msUntilAvailable(head.tokens);

      if (!isFinite(delay)) {
        // Permanently unsatisfiable — reject and advance to next waiter
        this._queue.shift();
        head.reject(
          new Error(
            `Cannot satisfy request for ${head.tokens} tokens: ` +
            `refill rate is 0 and bucket has only ${this._tokens} tokens available`
          )
        );
        continue;
      }

      this._timer = setTimeout(() => {
        this._timer = null;
        this._drain();
      }, Math.max(0, Math.ceil(delay)));
      return;
    }
  }

  private _drain(): void {
    while (this._queue.length > 0) {
      this._applyRefill();
      const head = this._queue[0];

      if (this._tokens >= head.tokens) {
        this._tokens -= head.tokens;
        this._queue.shift();
        head.resolve(); // schedules microtasks; does not execute synchronously
      } else {
        // Not enough tokens yet — reschedule for when they arrive
        this._scheduleNext();
        break;
      }
    }
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a non-negative finite number, got ${tokens}`);
    }
    if (tokens === 0) return true;

    this._applyRefill();

    if (this._tokens >= tokens) {
      this._tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this._applyRefill();
    return this._tokens;
  }

  reset(): void {
    this._tokens = this._maxTokens;
    this._lastRefillTime = Date.now();

    if (this._timer !== null) {
      clearTimeout(this._timer);
      this._timer = null;
    }

    // Give waiting callers a chance to be satisfied with the refilled bucket
    this._drain();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError(`tokens must be a non-negative finite number, got ${tokens}`)
      );
    }
    if (tokens === 0) return Promise.resolve();

    // A request larger than the bucket can never be satisfied regardless of refill
    if (tokens > this._maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maximum bucket capacity of ${this._maxTokens}`
        )
      );
    }

    // Fast path: no one waiting ahead and tokens are available right now
    if (this._queue.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this._queue.push({ tokens, resolve, reject });
      this._scheduleNext();
    });
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both = Sunday
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, field: CronField): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function expandRange(start: number, end: number, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  assertInRange(start, min, max, field);
  assertInRange(end, min, max, field);
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds range end ${end} for field "${field}"`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i++) values.push(i);
  return values;
}

function expandStep(rangeExpr: string, step: number, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (step <= 0) {
    throw new RangeError(`Step value must be a positive integer for field "${field}"`);
  }

  let start: number;
  let end: number;

  if (rangeExpr === "*") {
    start = min;
    end = max;
  } else if (/^\d+$/.test(rangeExpr)) {
    start = Number(rangeExpr);
    end = max;
    assertInRange(start, min, max, field);
  } else if (/^\d+-\d+$/.test(rangeExpr)) {
    const [s, e] = rangeExpr.split("-").map(Number);
    assertInRange(s, min, max, field);
    assertInRange(e, min, max, field);
    if (s > e) {
      throw new RangeError(
        `Range start ${s} exceeds range end ${e} for field "${field}"`
      );
    }
    start = s;
    end = e;
  } else {
    throw new SyntaxError(`Invalid range expression "${rangeExpr}" for field "${field}"`);
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) values.push(i);
  return values;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Step: */n or start/n or start-end/n
  if (segment.includes("/")) {
    const slashCount = (segment.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new SyntaxError(`Invalid step expression "${segment}" for field "${field}"`);
    }
    const slashIdx = segment.indexOf("/");
    const rangeExpr = segment.slice(0, slashIdx);
    const stepStr = segment.slice(slashIdx + 1);

    if (!/^\d+$/.test(stepStr)) {
      throw new SyntaxError(`Step must be a positive integer in "${segment}" for field "${field}"`);
    }
    const step = Number(stepStr);
    return expandStep(rangeExpr, step, field);
  }

  // Wildcard
  if (segment === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) values.push(i);
    return values;
  }

  // Range: n-m
  if (/^\d+-\d+$/.test(segment)) {
    const [start, end] = segment.split("-").map(Number);
    return expandRange(start, end, field);
  }

  // Literal number
  if (/^\d+$/.test(segment)) {
    const value = Number(segment);
    assertInRange(value, min, max, field);
    return [value];
  }

  throw new SyntaxError(`Unrecognized expression "${segment}" for field "${field}"`);
}

function parseField(expr: string, field: CronField): number[] {
  if (typeof expr !== "string" || expr.trim() === "") {
    throw new SyntaxError(`Empty or invalid expression for field "${field}"`);
  }

  const trimmed = expr.trim();

  // Guard against pathological input lengths
  if (trimmed.length > 256) {
    throw new SyntaxError(`Expression too long for field "${field}"`);
  }

  const segments = trimmed.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`No segments found for field "${field}"`);
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const s = segment.trim();
    if (s === "") {
      throw new SyntaxError(`Empty segment in list expression for field "${field}"`);
    }
    const expanded = parseSegment(s, field);
    for (const v of expanded) valueSet.add(v);
  }

  // Normalise dayOfWeek: treat 7 as 0 (Sunday)
  if (field === "dayOfWeek" && valueSet.has(7)) {
    valueSet.delete(7);
    valueSet.add(0);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Split on whitespace; guard against excess fields
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(fields[i], fieldName);
  }

  return result;
}

export default parseCron;
export type { CronResult, CronField };

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const sanitizedKey = String(key);
    const newKey = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

export type CronExpression = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_CONFIGS = [
  { name: "minute" as const, min: 0, max: 59 },
  { name: "hour" as const, min: 0, max: 23 },
  { name: "dayOfMonth" as const, min: 1, max: 31 },
  { name: "month" as const, min: 1, max: 12 },
  { name: "dayOfWeek" as const, min: 0, max: 6 },
] as const;

const DIGITS_RE = /^\d+$/;

function assertPositiveInt(value: number, label: string): void {
  if (!Number.isInteger(value) || value <= 0) {
    throw new RangeError(`${label} must be a positive integer, got ${value}`);
  }
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in segment "${context}"`
    );
  }
}

function strictParseInt(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!DIGITS_RE.test(trimmed)) {
    throw new SyntaxError(`Expected a non-negative integer, got "${raw}" in "${context}"`);
  }
  return parseInt(trimmed, 10);
}

function buildSequence(start: number, end: number, step: number): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

// Handles a single segment — no commas allowed here
function parseSegment(segment: string, min: number, max: number): number[] {
  if (segment === "*") {
    return buildSequence(min, max, 1);
  }

  // Wildcard with step: */N
  if (segment.startsWith("*/")) {
    const step = strictParseInt(segment.slice(2), segment);
    assertPositiveInt(step, `Step in "${segment}"`);
    return buildSequence(min, max, step);
  }

  // Range: A-B or A-B/N
  const rangeMatch = /^(\d+)-(\d+)(?:\/(\d+))?$/.exec(segment);
  if (rangeMatch) {
    const start = strictParseInt(rangeMatch[1], segment);
    const end = strictParseInt(rangeMatch[2], segment);
    const step = rangeMatch[3] !== undefined ? strictParseInt(rangeMatch[3], segment) : 1;

    assertPositiveInt(step, `Step in "${segment}"`);
    assertInRange(start, min, max, segment);
    assertInRange(end, min, max, segment);

    if (start > end) {
      throw new RangeError(
        `Range start (${start}) must be ≤ range end (${end}) in "${segment}"`
      );
    }

    return buildSequence(start, end, step);
  }

  // Step from value: N/step (generates from N to max)
  const stepFromMatch = /^(\d+)\/(\d+)$/.exec(segment);
  if (stepFromMatch) {
    const start = strictParseInt(stepFromMatch[1], segment);
    const step = strictParseInt(stepFromMatch[2], segment);

    assertPositiveInt(step, `Step in "${segment}"`);
    assertInRange(start, min, max, segment);

    return buildSequence(start, max, step);
  }

  // Single numeric value
  if (DIGITS_RE.test(segment)) {
    const value = parseInt(segment, 10);
    assertInRange(value, min, max, segment);
    return [value];
  }

  throw new SyntaxError(`Unrecognised cron field segment: "${segment}"`);
}

function parseField(field: string, min: number, max: number): number[] {
  const trimmed = field.trim();
  if (!trimmed) {
    throw new SyntaxError(`Cron field cannot be empty`);
  }

  if (!trimmed.includes(",")) {
    return parseSegment(trimmed, min, max);
  }

  const parts = trimmed.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    const cleaned = part.trim();
    if (!cleaned) {
      throw new SyntaxError(
        `Empty segment in comma-separated list "${field}" — check for trailing or double commas`
      );
    }
    for (const v of parseSegment(cleaned, min, max)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError(`Cron expression cannot be empty`);
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
        `but received ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    try {
      result[name] = parseField(fields[i], min, max);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new (err instanceof TypeError ? TypeError : err instanceof SyntaxError ? SyntaxError : RangeError)(
        `Invalid ${name} field ("${fields[i]}"): ${message}`
      );
    }
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function generateRange(start: number, end: number, step: number = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step with wildcard: */step
  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in segment: ${segment}`);
    }
    return generateRange(min, max, step);
  }

  // Range with optional step: start-end[/step]
  if (segment.includes("-")) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range in segment: ${segment}`);
    }
    clamp(start, min, max);
    clamp(end, min, max);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end}`);
    }
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in segment: ${segment}`);
    }
    return generateRange(start, end, step);
  }

  // Range with step but no explicit range start: value/step
  if (segment.includes("/")) {
    const [startStr, stepStr] = segment.split("/");
    const start = parseInt(startStr, 10);
    const step = parseInt(stepStr, 10);
    if (isNaN(start) || isNaN(step) || step <= 0) {
      throw new Error(`Invalid step expression in segment: ${segment}`);
    }
    clamp(start, min, max);
    return generateRange(start, max, step);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value in segment: ${segment}`);
  }
  clamp(value, min, max);
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (expression === "*") {
    return generateRange(min, max);
  }

  // Comma-separated list
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), min, max);
    for (const v of parsed) {
      // Normalize dayOfWeek: treat 7 as 0 (both represent Sunday)
      if (field === "dayOfWeek" && v === 7) {
        values.add(0);
      } else {
        values.add(v);
      }
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] =
    fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[];
  private timer: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;
    if (maxTokens <= 0) throw new RangeError("maxTokens must be positive");
    if (refillRate <= 0) throw new RangeError("refillRate must be positive");
    if (refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be positive");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waiters = [];
    this.timer = null;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime = now;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be positive");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    if (this.timer !== null) {
      clearTimeout(this.timer);
      this.timer = null;
    }

    this.processWaiters();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be positive");
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested tokens (${tokens}) exceeds maxTokens (${this.maxTokens}) and can never be fulfilled`
        )
      );
    }

    return new Promise<void>((resolve) => {
      // Only bypass the queue if no one is already waiting (preserves FIFO fairness)
      if (this.waiters.length === 0 && this.tryConsume(tokens)) {
        resolve();
        return;
      }

      this.waiters.push({ tokens, resolve });
      this.scheduleWakeup();
    });
  }

  private msUntilAvailable(needed: number): number {
    const deficit = needed - this.currentTokens;
    if (deficit <= 0) return 0;
    return (deficit / this.refillRate) * this.refillIntervalMs;
  }

  private processWaiters(): void {
    while (this.waiters.length > 0) {
      const waiter = this.waiters[0];

      this.refill();

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waiters.shift();
        waiter.resolve();
      } else {
        // Head-of-line: wait for the first waiter before serving the rest
        break;
      }
    }

    if (this.waiters.length > 0) {
      this.scheduleWakeup();
    }
  }

  private scheduleWakeup(): void {
    if (this.timer !== null || this.waiters.length === 0) return;

    this.refill();
    const delay = this.msUntilAvailable(this.waiters[0].tokens);

    this.timer = setTimeout(() => {
      this.timer = null;
      this.processWaiters();
    }, Math.max(0, delay));
  }
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0 && prefix) {
    result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new Error("maxTokens must be positive");
    if (options.refillRate <= 0) throw new Error("refillRate must be positive");
    if (options.refillIntervalMs <= 0) throw new Error("refillIntervalMs must be positive");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new Error("tokens must be positive");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new Error("tokens must be positive");
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new Error(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type FlatObject = Record<string, unknown>;

function flattenObject(
  input: Record<string, unknown>,
  prefix = "",
  seen = new WeakSet<object>()
): FlatObject {
  if (seen.has(input)) return {};
  seen.add(input);

  const result: FlatObject = {};

  for (const key of Object.keys(input)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = input[key];

    const isPlainObject =
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.getPrototypeOf(value) === Object.prototype;

    if (isPlainObject && Object.keys(value as object).length > 0) {
      Object.assign(
        result,
        flattenObject(value as Record<string, unknown>, fullKey, seen)
      );
    } else {
      result[fullKey] = value;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
