export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both = Sunday
};

function assertInRange(value: number, field: CronField): void {
  const { min, max } = FIELD_RANGES[field];
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}-${max}] for field "${field}"`
    );
  }
}

function dedup(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard: *
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Step: */n or range/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    if (segment.split("/").length !== 2) {
      throw new SyntaxError(`Invalid step expression "${segment}" in field "${field}"`);
    }

    const step = Number(stepPart);
    if (!Number.isInteger(step) || step < 1) {
      throw new RangeError(`Step value "${stepPart}" must be a positive integer in field "${field}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (!rangePart.includes("-")) {
        throw new SyntaxError(`Step base must be "*" or a range, got "${rangePart}" in field "${field}"`);
      }
      const [lo, hi] = rangePart.split("-").map(Number);
      assertInRange(lo, field);
      assertInRange(hi, field);
      if (lo > hi) {
        throw new RangeError(`Range start ${lo} > end ${hi} in field "${field}"`);
      }
      rangeMin = lo;
      rangeMax = hi;
    }

    const results: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      results.push(v);
    }
    return results;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    const lo = Number(parts[0]);
    const hi = Number(parts[1]);
    if (!Number.isFinite(lo) || !Number.isFinite(hi)) {
      throw new SyntaxError(`Non-numeric value in range "${segment}" for field "${field}"`);
    }
    assertInRange(lo, field);
    assertInRange(hi, field);
    if (lo > hi) {
      throw new RangeError(`Range start ${lo} > end ${hi} in field "${field}"`);
    }
    return Array.from({ length: hi - lo + 1 }, (_, i) => i + lo);
  }

  // Single number
  const num = Number(segment);
  if (!Number.isFinite(num) || segment.trim() === "") {
    throw new SyntaxError(`Invalid token "${segment}" in field "${field}"`);
  }
  assertInRange(num, field);
  return [num];
}

function parseField(raw: string, field: CronField): number[] {
  if (raw === undefined || raw === "") {
    throw new SyntaxError(`Empty value for field "${field}"`);
  }

  const values = raw
    .split(",")
    .flatMap((segment) => {
      if (segment === "") {
        throw new SyntaxError(`Empty segment in comma list for field "${field}"`);
      }
      return parseSegment(segment, field);
    });

  const result = dedup(values);

  // Normalise Sunday: treat 7 as 0 for dayOfWeek
  if (field === "dayOfWeek") {
    const normalised = dedup(result.map((v) => (v === 7 ? 0 : v)));
    return normalised;
  }

  return result;
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [rawMinute, rawHour, rawDayOfMonth, rawMonth, rawDayOfWeek] = fields;

  return {
    minute:     parseField(rawMinute,     "minute"),
    hour:       parseField(rawHour,       "hour"),
    dayOfMonth: parseField(rawDayOfMonth, "dayOfMonth"),
    month:      parseField(rawMonth,      "month"),
    dayOfWeek:  parseField(rawDayOfWeek,  "dayOfWeek"),
  };
}

export default parseCron;

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES: Record<keyof ParsedCron, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const isUnsignedInt = (s: string): boolean => /^\d+$/.test(s);

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}–${max}] in segment "${context}"`
    );
  }
}

function parseRange(token: string, min: number, max: number): [number, number] {
  const dashIdx = token.indexOf('-');
  if (dashIdx === -1) {
    throw new SyntaxError(`Expected range with "-" in "${token}"`);
  }
  const startStr = token.slice(0, dashIdx);
  const endStr = token.slice(dashIdx + 1);

  if (!isUnsignedInt(startStr) || !isUnsignedInt(endStr)) {
    throw new SyntaxError(`Invalid range "${token}"`);
  }

  const start = parseInt(startStr, 10);
  const end   = parseInt(endStr,   10);

  assertInBounds(start, min, max, token);
  assertInBounds(end,   min, max, token);

  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end} in "${token}"`);
  }

  return [start, end];
}

function expandSegment(token: string, min: number, max: number): number[] {
  // Step expression: */n  |  a-b/n  |  a/n
  const slashIdx = token.indexOf('/');
  if (slashIdx !== -1) {
    const baseStr = token.slice(0, slashIdx);
    const stepStr = token.slice(slashIdx + 1);

    if (!isUnsignedInt(stepStr)) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in "${token}"`);
    }

    const step = parseInt(stepStr, 10);
    if (step === 0) {
      throw new RangeError(`Step cannot be zero in "${token}"`);
    }

    let start: number;
    let end: number;

    if (baseStr === '*') {
      start = min;
      end   = max;
    } else if (baseStr.includes('-')) {
      [start, end] = parseRange(baseStr, min, max);
    } else {
      if (!isUnsignedInt(baseStr)) {
        throw new SyntaxError(`Invalid base value "${baseStr}" in "${token}"`);
      }
      start = parseInt(baseStr, 10);
      end   = max;
      assertInBounds(start, min, max, token);
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (token === '*') {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Range: a-b
  if (token.includes('-')) {
    const [start, end] = parseRange(token, min, max);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single integer
  if (!isUnsignedInt(token)) {
    throw new SyntaxError(`Invalid cron token "${token}"`);
  }
  const num = parseInt(token, 10);
  assertInBounds(num, min, max, token);
  return [num];
}

function expandField(expression: string, min: number, max: number): number[] {
  const parts = expression.split(',');

  for (const part of parts) {
    if (part === '') {
      throw new SyntaxError(
        `Empty element in comma-separated field "${expression}"`
      );
    }
  }

  const seen = new Set<number>();
  for (const part of parts) {
    for (const v of expandSegment(part, min, max)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== 'string') {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === '') {
    throw new SyntaxError('Cron expression cannot be empty');
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (got ${fields.length}): "${expression}"`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;

  return {
    minute:     expandField(minuteStr, FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max),
    hour:       expandField(hourStr,   FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max),
    dayOfMonth: expandField(domStr,    FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max),
    month:      expandField(monthStr,  FIELD_RANGES.month.min,      FIELD_RANGES.month.max),
    dayOfWeek:  expandField(dowStr,    FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max),
  };
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  seen = new WeakSet<object>()
): Record<string, unknown> {
  if (seen.has(obj)) {
    throw new Error(
      `Circular reference detected${prefix ? ` at key "${prefix}"` : ""}`
    );
  }

  seen.add(obj);
  const result: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(obj)) {
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      const nested = flattenObject(value, fullKey, seen);
      Object.assign(result, nested);
    } else {
      result[fullKey] = value;
    }
  }

  // Remove after processing so shared (non-circular) references don't false-positive
  seen.delete(obj);

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both = Sunday
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, field: CronField): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] for field "${field}"`
    );
  }
}

function expandRange(start: number, end: number, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  assertInRange(start, min, max, field);
  assertInRange(end, min, max, field);
  if (start > end) {
    throw new RangeError(
      `Range start ${start} must not exceed range end ${end} for field "${field}"`
    );
  }
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard: "*"
  if (segment === "*") {
    const all: number[] = [];
    for (let i = min; i <= max; i++) all.push(i);
    return all;
  }

  // Step: "*/N" or "start-end/N"
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const baseStr = segment.slice(0, slashIdx);
    const stepStr = segment.slice(slashIdx + 1);

    const step = Number(stepStr);
    if (!Number.isInteger(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (baseStr === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (baseStr.includes("-")) {
      const [startStr, endStr] = baseStr.split("-");
      rangeMin = Number(startStr);
      rangeMax = Number(endStr);
      if (!Number.isInteger(rangeMin) || !Number.isInteger(rangeMax)) {
        throw new SyntaxError(`Invalid range "${baseStr}" in field "${field}"`);
      }
      assertInRange(rangeMin, min, max, field);
      assertInRange(rangeMax, min, max, field);
      if (rangeMin > rangeMax) {
        throw new RangeError(
          `Range start ${rangeMin} must not exceed range end ${rangeMax} for field "${field}"`
        );
      }
    } else {
      rangeMin = Number(baseStr);
      if (!Number.isInteger(rangeMin)) {
        throw new SyntaxError(`Invalid step base "${baseStr}" in field "${field}"`);
      }
      assertInRange(rangeMin, min, max, field);
      rangeMax = max;
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) result.push(i);
    return result;
  }

  // Range: "N-M"
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    const start = Number(parts[0]);
    const end = Number(parts[1]);
    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new SyntaxError(`Non-integer range bounds in "${segment}" for field "${field}"`);
    }
    return expandRange(start, end, field);
  }

  // Plain number
  const value = Number(segment);
  if (!Number.isInteger(value) || segment.trim() === "") {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  assertInRange(value, min, max, field);
  return [value];
}

function parseField(expr: string, field: CronField): number[] {
  if (expr === "" || expr.trim() === "") {
    throw new SyntaxError(`Empty expression for field "${field}"`);
  }

  const segments = expr.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in list expression for field "${field}"`);
    }
    for (const v of parseSegment(trimmed, field)) {
      // Normalize: treat 7 (Sunday alias) as 0 for dayOfWeek
      if (field === "dayOfWeek" && v === 7) {
        valueSet.add(0);
      } else {
        valueSet.add(v);
      }
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string expression, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Collapse internal whitespace to single spaces and split on whitespace
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected exactly 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private pendingCheck: ReturnType<typeof setTimeout> | null;

  constructor({ maxTokens, refillRate, refillIntervalMs }: RateLimiterOptions) {
    if (maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.pendingCheck = null;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate,
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const { tokens, resolve } = this.waitQueue[0];
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        this.waitQueue.shift();
        resolve();
      } else {
        break;
      }
    }
  }

  private scheduleRefillCheck(): void {
    if (this.pendingCheck !== null) return;

    const elapsed = Date.now() - this.lastRefillTime;
    const delay = this.refillIntervalMs - (elapsed % this.refillIntervalMs);

    this.pendingCheck = setTimeout(() => {
      this.pendingCheck = null;
      this.refill();
      this.drainQueue();

      if (this.waitQueue.length > 0) {
        this.scheduleRefillCheck();
      }
    }, delay);
  }

  tryConsume(tokens = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    // Respect FIFO ordering: don't bypass callers waiting in queue
    if (this.waitQueue.length > 0) return false;

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} token(s) exceeds bucket capacity of ${this.maxTokens}`,
        ),
      );
    }

    this.refill();

    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleRefillCheck();
    });
  }
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private scheduledCheck: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (maxTokens <= 0) throw new RangeError("maxTokens must be positive");
    if (refillRate <= 0) throw new RangeError("refillRate must be positive");
    if (refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be positive");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledCheck = null;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens < 0) throw new RangeError("tokens must be non-negative");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    if (this.scheduledCheck !== null) {
      clearTimeout(this.scheduledCheck);
      this.scheduledCheck = null;
    }

    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens < 0) throw new RangeError("tokens must be non-negative");
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`)
      );
    }

    if (this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleCheck();
    });
  }

  private scheduleCheck(): void {
    if (this.scheduledCheck !== null || this.waitQueue.length === 0) return;

    this.refill();

    const nextItem = this.waitQueue[0];
    const deficit = nextItem.tokens - this.currentTokens;

    const delayMs =
      deficit <= 0
        ? 0
        : Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);

    this.scheduledCheck = setTimeout(() => {
      this.scheduledCheck = null;
      this.drainQueue();
    }, delayMs);
  }

  private drainQueue(): void {
    this.refill();

    while (this.waitQueue.length > 0) {
      const item = this.waitQueue[0];

      if (this.currentTokens >= item.tokens) {
        this.currentTokens -= item.tokens;
        this.waitQueue.shift();
        item.resolve();
      } else {
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleCheck();
    }
  }
}

export default RateLimiter;

type PlainObject = Record<string, unknown>;

interface FlattenOptions {
  delimiter?: string;
}

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value) as unknown;
  return proto === Object.prototype || proto === null;
}

function flattenRecursive(
  obj: PlainObject,
  prefix: string,
  delimiter: string,
  result: PlainObject,
  ancestors: WeakSet<object>,
): void {
  ancestors.add(obj);

  for (const key of Object.keys(obj)) {
    const fullKey = prefix.length > 0 ? `${prefix}${delimiter}${key}` : key;
    const value = obj[key];

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      if (ancestors.has(value)) {
        throw new TypeError(`Circular reference detected at key "${fullKey}"`);
      }
      flattenRecursive(value, fullKey, delimiter, result, ancestors);
    } else {
      // Leaf values: primitives, null, arrays, Date, RegExp, Map, Set,
      // functions, empty plain objects, and anything else non-plain-object.
      result[fullKey] = value;
    }
  }

  // Backtrack so sibling branches can legitimately reuse the same reference.
  ancestors.delete(obj);
}

function flattenObject(input: unknown, options: FlattenOptions = {}): PlainObject {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : Array.isArray(input) ? "array" : typeof input
      }`,
    );
  }

  const delimiter = options.delimiter ?? ".";

  if (typeof delimiter !== "string" || delimiter.length === 0) {
    throw new TypeError("options.delimiter must be a non-empty string");
  }

  const result: PlainObject = {};
  const ancestors = new WeakSet<object>();

  flattenRecursive(input, "", delimiter, result, ancestors);

  return result;
}

export default flattenObject;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${options.maxTokens}`);
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got ${options.refillRate}`);
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyLazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) {
      return;
    }

    const intervals = elapsed / this.refillIntervalMs;
    const tokensToAdd = intervals * this.refillRate;

    if (tokensToAdd >= 1e-9) {
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime = now;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a non-negative finite number, got ${tokens}`);
    }
    if (tokens > this.maxTokens) {
      return false;
    }
    if (tokens === 0) {
      return true;
    }

    this.applyLazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyLazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(new RangeError(`tokens must be a non-negative finite number, got ${tokens}`));
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; will never be satisfiable`
        )
      );
    }
    if (tokens === 0) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.applyLazyRefill();
        const deficit = tokens - this.currentTokens;
        const msPerToken = this.refillIntervalMs / this.refillRate;
        const waitMs = Math.ceil(deficit * msPerToken);
        const clampedWait = Math.max(1, waitMs);

        setTimeout(attempt, clampedWait);
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  readonly tokens: number;
  readonly resolve: () => void;
  readonly reject: (error: Error) => void;
}

export default class RateLimiter {
  private readonly _maxTokens: number;
  private readonly _refillRate: number;
  private readonly _refillIntervalMs: number;

  private _tokens: number;
  private _lastRefillTime: number;
  private readonly _waiters: Waiter[];
  private _refillTimer: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(
        `maxTokens must be a positive finite number, got ${maxTokens}`
      );
    }
    if (!Number.isFinite(refillRate) || refillRate < 0) {
      throw new RangeError(
        `refillRate must be a non-negative finite number, got ${refillRate}`
      );
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(
        `refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`
      );
    }

    this._maxTokens = maxTokens;
    this._refillRate = refillRate;
    this._refillIntervalMs = refillIntervalMs;
    this._tokens = maxTokens;
    this._lastRefillTime = Date.now();
    this._waiters = [];
    this._refillTimer = null;
  }

  // Lazily accumulate tokens based on elapsed wall-clock time.
  // Guards against negative elapsed time to survive clock skew or mocked clocks.
  private _applyRefill(): void {
    const now = Date.now();
    const elapsed = Math.max(0, now - this._lastRefillTime);
    this._lastRefillTime = now;

    if (elapsed > 0 && this._refillRate > 0) {
      this._tokens = Math.min(
        this._maxTokens,
        this._tokens + (elapsed / this._refillIntervalMs) * this._refillRate
      );
    }
  }

  // Returns how many milliseconds until `needed` tokens are available,
  // given the current bucket state (call _applyRefill first).
  private _msUntilAvailable(needed: number): number {
    const deficit = needed - this._tokens;
    if (deficit <= 0) return 0;
    if (this._refillRate <= 0) return Infinity;
    return (deficit / this._refillRate) * this._refillIntervalMs;
  }

  // Attempt to satisfy queued waiters in FIFO order, then reschedule if needed.
  private _drainQueue(): void {
    if (this._refillTimer !== null) {
      clearTimeout(this._refillTimer);
      this._refillTimer = null;
    }

    this._applyRefill();

    while (this._waiters.length > 0) {
      const waiter = this._waiters[0]!;
      if (this._tokens >= waiter.tokens) {
        this._tokens -= waiter.tokens;
        this._waiters.shift();
        waiter.resolve();
      } else {
        // Head-of-line waiter not yet satisfiable; stop (preserve fairness).
        break;
      }
    }

    // Reschedule for the next waiter if refill is possible.
    if (this._waiters.length > 0 && this._refillRate > 0) {
      const delay = this._msUntilAvailable(this._waiters[0]!.tokens);
      this._refillTimer = setTimeout(() => {
        this._refillTimer = null;
        this._drainQueue();
      }, delay);
    }
    // If refillRate === 0 and waiters remain, only reset() can unblock them.
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(
        `tokens must be a positive finite number, got ${tokens}`
      );
    }
    // Exceeds capacity unconditionally — return false rather than throw,
    // since a caller might legitimately probe for availability.
    if (tokens > this._maxTokens) {
      return false;
    }

    this._applyRefill();

    if (this._tokens >= tokens) {
      this._tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this._applyRefill();
    return this._tokens;
  }

  reset(): void {
    this._tokens = this._maxTokens;
    this._lastRefillTime = Date.now();
    // Drain queue immediately — reset to full capacity may satisfy pending waiters.
    this._drainQueue();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(
        `tokens must be a positive finite number, got ${tokens}`
      );
    }
    // A request exceeding maxTokens can never be fulfilled — fail eagerly
    // rather than blocking the caller indefinitely with no signal.
    if (tokens > this._maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds maxTokens (${this._maxTokens}) ` +
          `and can never be satisfied`
      );
    }

    // Fast path: skip the queue if no one is ahead and tokens are available.
    // Bypassing the queue when _waiters is non-empty preserves FIFO fairness.
    if (this._waiters.length === 0 && this.tryConsume(tokens)) {
      return;
    }

    return new Promise<void>((resolve, reject) => {
      this._waiters.push({ tokens, resolve, reject });

      // Only schedule a drain if one is not already pending.
      // Invariant: _refillTimer !== null whenever _waiters is non-empty
      // and _refillRate > 0, maintained by _drainQueue and here.
      if (this._refillTimer === null && this._refillRate > 0) {
        // Re-apply refill so the delay is computed from accurate current state.
        this._applyRefill();
        const delay = this._msUntilAvailable(this._waiters[0]!.tokens);
        this._refillTimer = setTimeout(() => {
          this._refillTimer = null;
          this._drainQueue();
        }, delay);
      }
    });
  }
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = Record<string, unknown>;

function isTraversable(value: unknown): value is NestedObject | unknown[] {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  // Only recurse into plain objects and arrays; treat Date, RegExp, Map, Set, etc. as leaves
  return proto === Object.prototype || proto === null || Array.isArray(value);
}

function flatten(
  value: object,
  prefix: string,
  result: FlatObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(value)) {
    // Circular reference detected — treat node as a leaf to avoid infinite loop
    result[prefix] = value;
    return;
  }

  const entries = Object.entries(value);

  if (entries.length === 0) {
    // Empty object/array — preserve the key so the caller knows this path existed
    if (prefix !== "") result[prefix] = value;
    return;
  }

  ancestors.add(value);

  for (const [key, child] of entries) {
    const fullKey = prefix !== "" ? `${prefix}.${key}` : key;

    if (isTraversable(child)) {
      flatten(child as object, fullKey, result, ancestors);
    } else {
      result[fullKey] = child;
    }
  }

  // Backtrack so the same object can safely appear in sibling branches
  ancestors.delete(value);
}

function flattenObject(obj: NestedObject): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    throw new TypeError(`flattenObject expects a plain object, got: ${Array.isArray(obj) ? "array" : String(obj)}`);
  }

  const result: FlatObject = {};
  flatten(obj, "", result, new WeakSet());
  return result;
}

export default flattenObject;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[] = [];
  private queueTimer: ReturnType<typeof setTimeout> | null = null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens < 0)
      throw new RangeError("maxTokens must be a non-negative finite number");
    if (!Number.isFinite(refillRate) || refillRate < 0)
      throw new RangeError("refillRate must be a non-negative finite number");
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs < 0)
      throw new RangeError("refillIntervalMs must be a non-negative finite number");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    if (this.refillRate <= 0 || this.refillIntervalMs <= 0) return;

    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervalsElapsed * this.refillRate
      );
      // Advance by whole intervals only — preserves fractional remainder for next refill
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0)
      throw new RangeError("tokens must be a non-negative finite number");
    if (tokens === 0) return true;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    if (this.queueTimer !== null) {
      clearTimeout(this.queueTimer);
      this.queueTimer = null;
    }

    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    // Give pending waiters a chance to run now that the bucket is full
    this.drainQueue();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0)
      return Promise.reject(new RangeError("tokens must be a non-negative finite number"));
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} token(s) exceeds bucket capacity of ${this.maxTokens}`
        )
      );

    this.refill();

    // Fast path: no backlog and sufficient tokens
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    // If refill is disabled and we can't satisfy the request now, it will never resolve
    if (this.refillRate <= 0 || this.refillIntervalMs <= 0) {
      return Promise.reject(
        new Error(
          "Cannot wait for tokens: refill is disabled and current tokens are insufficient"
        )
      );
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleQueue();
    });
  }

  private scheduleQueue(): void {
    // Only one timer runs at a time; it re-schedules itself through drainQueue if needed
    if (this.queueTimer !== null || this.waitQueue.length === 0) return;

    this.refill();

    const waiter = this.waitQueue[0];
    const tokenDeficit = waiter.tokens - this.currentTokens;

    if (tokenDeficit <= 0) {
      // Defer to next tick to avoid re-entrancy surprises
      this.queueTimer = setTimeout(() => {
        this.queueTimer = null;
        this.drainQueue();
      }, 0);
      return;
    }

    // Time remaining in the current (already partially elapsed) interval
    const elapsedSinceLastRefill = Date.now() - this.lastRefillTime;
    const timeUntilNextInterval = this.refillIntervalMs - elapsedSinceLastRefill;

    // How many full intervals we need to cover the deficit
    const intervalsNeeded = Math.ceil(tokenDeficit / this.refillRate);

    // First interval fires at timeUntilNextInterval; each subsequent one is refillIntervalMs later
    const waitMs = timeUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs;

    this.queueTimer = setTimeout(() => {
      this.queueTimer = null;
      this.drainQueue();
    }, Math.max(0, waitMs));
  }

  private drainQueue(): void {
    this.refill();

    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        // Tokens not yet available for the head of the queue; schedule next wake-up
        this.scheduleQueue();
        return;
      }
    }
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldBounds {
  min: number;
  max: number;
}

const FIELD_BOUNDS: Record<CronField, FieldBounds> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both = Sunday
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, bounds: FieldBounds, context: string): void {
  if (!Number.isInteger(value) || value < bounds.min || value > bounds.max) {
    throw new RangeError(
      `Value ${value} out of range [${bounds.min}-${bounds.max}] in field "${context}"`
    );
  }
}

function expandRange(
  rawStart: string,
  rawEnd: string,
  bounds: FieldBounds,
  field: CronField
): number[] {
  const start = Number(rawStart);
  const end = Number(rawEnd);

  if (!Number.isFinite(start) || !Number.isFinite(end)) {
    throw new TypeError(`Non-numeric range boundary in field "${field}"`);
  }

  assertInRange(start, bounds, field);
  assertInRange(end, bounds, field);

  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${field}"`
    );
  }

  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function expandStep(
  baseExpr: string,
  rawStep: string,
  bounds: FieldBounds,
  field: CronField
): number[] {
  const step = Number(rawStep);

  if (!Number.isInteger(step) || step < 1) {
    throw new RangeError(
      `Step value must be a positive integer, got "${rawStep}" in field "${field}"`
    );
  }

  let candidates: number[];

  if (baseExpr === "*") {
    candidates = [];
    for (let i = bounds.min; i <= bounds.max; i++) candidates.push(i);
  } else if (baseExpr.includes("-")) {
    const [rs, re] = baseExpr.split("-");
    candidates = expandRange(rs, re, bounds, field);
  } else {
    const start = Number(baseExpr);
    if (!Number.isInteger(start)) {
      throw new TypeError(`Invalid step base "${baseExpr}" in field "${field}"`);
    }
    assertInRange(start, bounds, field);
    candidates = [];
    for (let i = start; i <= bounds.max; i++) candidates.push(i);
  }

  return candidates.filter((_, idx) => idx % step === 0);
}

function parseSegment(
  segment: string,
  bounds: FieldBounds,
  field: CronField
): number[] {
  // Step value: base/step (base = *, number, or range)
  if (segment.includes("/")) {
    const slashCount = (segment.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new SyntaxError(`Multiple "/" in segment "${segment}" of field "${field}"`);
    }
    const slashIdx = segment.indexOf("/");
    const base = segment.slice(0, slashIdx);
    const step = segment.slice(slashIdx + 1);
    if (!base || !step) {
      throw new SyntaxError(`Malformed step expression "${segment}" in field "${field}"`);
    }
    return expandStep(base, step, bounds, field);
  }

  // Wildcard
  if (segment === "*") {
    const result: number[] = [];
    for (let i = bounds.min; i <= bounds.max; i++) result.push(i);
    return result;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    return expandRange(parts[0], parts[1], bounds, field);
  }

  // Plain number
  const value = Number(segment);
  if (!Number.isInteger(value) || !Number.isFinite(value)) {
    throw new TypeError(`Non-numeric value "${segment}" in field "${field}"`);
  }
  assertInRange(value, bounds, field);
  return [value];
}

function parseField(raw: string, bounds: FieldBounds, field: CronField): number[] {
  if (raw === undefined || raw === null || raw.trim() === "") {
    throw new SyntaxError(`Empty value for field "${field}"`);
  }

  const segments = raw.split(",");
  if (segments.some((s) => s.trim() === "")) {
    throw new SyntaxError(
      `Empty segment in comma-separated list for field "${field}": "${raw}"`
    );
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment.trim(), bounds, field);
    for (const v of values) valueSet.add(v);
  }

  // Normalise dayOfWeek: treat 7 (alt Sunday) as 0
  if (field === "dayOfWeek") {
    if (valueSet.has(7)) {
      valueSet.delete(7);
      valueSet.add(0);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Guard against shell injection or absurdly long inputs
  if (trimmed.length > 256) {
    throw new SyntaxError("Cron expression exceeds maximum allowed length of 256 characters");
  }

  // Only allow characters that belong in a valid cron expression
  if (!/^[\d\s\*\-,/]+$/.test(trimmed)) {
    throw new SyntaxError(
      `Cron expression contains invalid characters: "${trimmed}"`
    );
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    const bounds = FIELD_BOUNDS[field];
    result[field] = parseField(fields[i], bounds, field);

    if (result[field].length === 0) {
      throw new RangeError(
        `Field "${field}" resolved to an empty set of values — check expression "${fields[i]}"`
      );
    }
  }

  return result;
}

export default parseCron;

type Waiter = {
  readonly tokens: number;
  readonly resolve: () => void;
  readonly reject: (error: Error) => void;
};

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private drainTimer: ReturnType<typeof setTimeout> | null;

  constructor(options: { maxTokens: number; refillRate: number; refillIntervalMs: number }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a finite non-negative number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.drainTimer = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    // Guard against clock skew or monotonic drift — never subtract tokens on backward clock
    const elapsed = Math.max(0, now - this.lastRefillTime);
    this.lastRefillTime = now;

    if (elapsed === 0 || this.refillRate === 0 || this.currentTokens >= this.maxTokens) return;

    const added = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens === 0) return true;
    // A request larger than the bucket can never succeed, even when full
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // A reset may unblock queued waiters — attempt to drain them
    this.drainQueue();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(new RangeError("tokens must be a finite non-negative number"));
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds the maximum bucket capacity of ${this.maxTokens} — can never be satisfied`
        )
      );
    }

    this.applyRefill();

    // Fast path: no queue backlog and sufficient tokens available right now
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    // Slow path: enqueue and wait — FIFO ordering prevents large-request starvation
    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextDrain();
    });
  }

  private drainQueue(): void {
    if (this.drainTimer !== null) {
      clearTimeout(this.drainTimer);
      this.drainTimer = null;
    }

    while (this.waitQueue.length > 0) {
      this.applyRefill();
      const head = this.waitQueue[0]!;

      if (this.currentTokens >= head.tokens) {
        this.currentTokens -= head.tokens;
        this.waitQueue.shift();
        // Resolve outside the loop iteration to avoid re-entrancy surprises
        // (resolve is synchronous here; queueMicrotask would be safer but adds complexity)
        head.resolve();
      } else {
        // Head cannot be served yet — schedule a wake-up for when it can be
        this.scheduleNextDrain();
        return;
      }
    }
  }

  private scheduleNextDrain(): void {
    // Already scheduled or nothing to drain
    if (this.drainTimer !== null || this.waitQueue.length === 0) return;

    // If refillRate is zero, no tokens will ever arrive — reject all waiters immediately
    if (this.refillRate === 0) {
      const error = new Error(
        "Rate limiter stalled: refillRate is 0 and insufficient tokens remain to satisfy waitForTokens"
      );
      for (const waiter of this.waitQueue.splice(0)) {
        waiter.reject(error);
      }
      return;
    }

    // Re-apply refill so deficit calculation is based on the current moment
    this.applyRefill();
    const head = this.waitQueue[0]!;
    const deficit = Math.max(0, head.tokens - this.currentTokens);
    const tokensPerMs = this.refillRate / this.refillIntervalMs;
    // Ceil to guarantee we wake up with enough tokens, not just barely short
    const delayMs = Math.ceil(deficit / tokensPerMs);

    this.drainTimer = setTimeout(() => {
      this.drainTimer = null;
      this.drainQueue();
    }, delayMs);
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError("refillRate must be a positive finite number");
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervalsElapsed * this.refillRate
      );
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("tokens must be a positive finite number");
    }
    // Can never be satisfied regardless of refill state
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("tokens must be a positive finite number");
    }
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds maximum bucket capacity of ${this.maxTokens}`
      );
    }

    // JS is single-threaded: the while loop + re-check after each await is
    // sufficient to handle multiple concurrent waitForTokens callers without
    // starvation — only one microtask runs at a time.
    while (true) {
      this.refill();

      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return;
      }

      // Compute a targeted sleep: how many more full refill intervals are
      // needed, offset by however far into the current interval we already are.
      const tokensNeeded = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
      const elapsedSinceLastRefill = Date.now() - this.lastRefillTime;
      const msUntilNextInterval = this.refillIntervalMs - elapsedSinceLastRefill;
      const waitMs = msUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs;

      await new Promise<void>((resolve) =>
        setTimeout(resolve, Math.max(0, waitMs))
      );
    }
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object") {
    return result;
  }

  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = (obj as Record<string, unknown>)[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function parseIntStrict(s: string, context: string): number {
  const trimmed = s.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Invalid integer "${s}" in: "${context}"`);
  }
  return parseInt(trimmed, 10);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in: "${context}"`
    );
  }
}

function expandRange(start: number, end: number, step = 1): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step value: */n, start-end/n, or start/n
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const step = parseIntStrict(segment.slice(slashIdx + 1), segment);
    if (step < 1) {
      throw new RangeError(`Step value must be >= 1 in: "${segment}"`);
    }

    const rangePart = segment.slice(0, slashIdx);
    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const dashIdx = rangePart.indexOf("-");
      start = parseIntStrict(rangePart.slice(0, dashIdx), segment);
      end = parseIntStrict(rangePart.slice(dashIdx + 1), segment);
      assertInRange(start, min, max, segment);
      assertInRange(end, min, max, segment);
      if (start > end) {
        throw new Error(`Range start (${start}) must be <= end (${end}) in: "${segment}"`);
      }
    } else {
      start = parseIntStrict(rangePart, segment);
      end = max;
      assertInRange(start, min, max, segment);
    }

    return expandRange(start, end, step);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const start = parseIntStrict(segment.slice(0, dashIdx), segment);
    const end = parseIntStrict(segment.slice(dashIdx + 1), segment);
    assertInRange(start, min, max, segment);
    assertInRange(end, min, max, segment);
    if (start > end) {
      throw new Error(`Range start (${start}) must be <= end (${end}) in: "${segment}"`);
    }
    return expandRange(start, end);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max);
  }

  // Single number
  const num = parseIntStrict(segment, segment);
  assertInRange(num, min, max, segment);
  return [num];
}

function parseField(field: string, min: number, max: number): number[] {
  if (field.includes(",")) {
    const valueSet = new Set<number>();
    for (const segment of field.split(",")) {
      for (const v of parseSegment(segment.trim(), min, max)) {
        valueSet.add(v);
      }
    }
    return Array.from(valueSet).sort((a, b) => a - b);
  }
  return parseSegment(field, min, max);
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields but got ${fields.length} in: "${expression}"`
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = fields;

  return {
    minute: parseField(minuteStr, 0, 59),
    hour: parseField(hourStr, 0, 23),
    dayOfMonth: parseField(dayOfMonthStr, 1, 31),
    month: parseField(monthStr, 1, 12),
    dayOfWeek: parseField(dayOfWeekStr, 0, 6),
  };
}

export default parseCron;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function expandRange(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInBounds(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of bounds [${config.min}–${config.max}] in "${context}"`,
    );
  }
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Step: */n or start/n or start-end/n
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const rangeStr = segment.slice(0, slashIdx);
    const stepStr  = segment.slice(slashIdx + 1);
    const step     = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value "${stepStr}" in "${segment}"`);
    }

    let start: number;
    let end: number;

    if (rangeStr === "*") {
      start = min;
      end   = max;
    } else if (rangeStr.includes("-")) {
      const [lo, hi] = rangeStr.split("-").map(Number);
      if (isNaN(lo) || isNaN(hi)) {
        throw new TypeError(`Invalid range "${rangeStr}" in step expression "${segment}"`);
      }
      assertInBounds(lo, config, segment);
      assertInBounds(hi, config, segment);
      if (lo > hi) throw new RangeError(`Start ${lo} > end ${hi} in "${segment}"`);
      start = lo;
      end   = hi;
    } else {
      const lo = parseInt(rangeStr, 10);
      if (isNaN(lo)) throw new TypeError(`Invalid start value "${rangeStr}" in "${segment}"`);
      assertInBounds(lo, config, segment);
      start = lo;
      end   = max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new TypeError(`Invalid range "${segment}"`);
    const start = parseInt(parts[0], 10);
    const end   = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) throw new TypeError(`Invalid range "${segment}"`);
    assertInBounds(start, config, segment);
    assertInBounds(end,   config, segment);
    if (start > end) throw new RangeError(`Start ${start} > end ${end} in "${segment}"`);
    return expandRange(start, end);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) throw new TypeError(`Unrecognised cron token "${segment}"`);
  assertInBounds(num, config, segment);
  return [num];
}

function parseField(field: string, config: FieldConfig): number[] {
  // Comma-separated list: parse each part, merge, dedup, sort
  const parts = field.split(",");
  if (parts.length > 1) {
    const values = parts.flatMap(part => parseSegment(part.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }
  return parseSegment(field.trim(), config);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new TypeError(
      `Cron expression must have exactly 5 fields (got ${fields.length}): "${expression}"`,
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = fields;

  return {
    minute:     parseField(minuteStr,     FIELD_CONFIGS.minute),
    hour:       parseField(hourStr,       FIELD_CONFIGS.hour),
    dayOfMonth: parseField(dayOfMonthStr, FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthStr,      FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dayOfWeekStr,  FIELD_CONFIGS.dayOfWeek),
  };
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function buildRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function assertWithinBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Comma-separated list — recurse per element, deduplicate, sort
  if (segment.includes(",")) {
    const seen = new Set<number>();
    for (const part of segment.split(",")) {
      for (const v of parseSegment(part.trim(), min, max)) seen.add(v);
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  // Step expression: */n  |  start/n  |  start-end/n
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const rangeStr = segment.slice(0, slashIdx);
    const stepStr  = segment.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new TypeError(`Invalid step "${stepStr}" in "${segment}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (rangeStr === "*") {
      rangeStart = min;
      rangeEnd   = max;
    } else if (rangeStr.includes("-")) {
      [rangeStart, rangeEnd] = parseDashRange(rangeStr, min, max);
    } else {
      rangeStart = parseInt(rangeStr, 10);
      if (isNaN(rangeStart)) throw new TypeError(`Invalid start "${rangeStr}" in "${segment}"`);
      assertWithinBounds(rangeStart, min, max, segment);
      rangeEnd = max;
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) values.push(i);
    return values;
  }

  // Range expression: start-end
  if (segment.includes("-")) {
    const [start, end] = parseDashRange(segment, min, max);
    return buildRange(start, end);
  }

  // Wildcard
  if (segment === "*") return buildRange(min, max);

  // Single integer
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new TypeError(`Invalid token "${segment}"`);
  assertWithinBounds(value, min, max, segment);
  return [value];
}

function parseDashRange(token: string, min: number, max: number): [number, number] {
  const parts = token.split("-");
  if (parts.length !== 2) throw new TypeError(`Invalid range "${token}"`);
  const start = parseInt(parts[0], 10);
  const end   = parseInt(parts[1], 10);
  if (isNaN(start) || isNaN(end)) throw new TypeError(`Non-numeric range values in "${token}"`);
  assertWithinBounds(start, min, max, token);
  assertWithinBounds(end,   min, max, token);
  if (start > end) throw new RangeError(`Range start ${start} > end ${end} in "${token}"`);
  return [start, end];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new TypeError(
      `Cron expression must have exactly 5 fields; got ${fields.length}: "${expression}"`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;

  return {
    minute:     parseSegment(minuteStr, FIELD_CONFIGS.minute.min,     FIELD_CONFIGS.minute.max),
    hour:       parseSegment(hourStr,   FIELD_CONFIGS.hour.min,       FIELD_CONFIGS.hour.max),
    dayOfMonth: parseSegment(domStr,    FIELD_CONFIGS.dayOfMonth.min, FIELD_CONFIGS.dayOfMonth.max),
    month:      parseSegment(monthStr,  FIELD_CONFIGS.month.min,      FIELD_CONFIGS.month.max),
    dayOfWeek:  parseSegment(dowStr,    FIELD_CONFIGS.dayOfWeek.min,  FIELD_CONFIGS.dayOfWeek.max),
  };
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint;

type FlattenedObject = Record<string, Primitive>;

function flattenObject(
  input: Record<string, unknown>,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (input === null || typeof input !== "object") {
    throw new TypeError(`Expected a plain object, got ${typeof input}`);
  }

  for (const key of Object.keys(input)) {
    if (key.length === 0) {
      // Empty string keys would produce malformed dot-notation paths — skip them
      continue;
    }

    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = (input as Record<string, unknown>)[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp) &&
      !(value instanceof Map) &&
      !(value instanceof Set)
    ) {
      const nested = value as Record<string, unknown>;

      if (Object.keys(nested).length === 0) {
        // Preserve empty objects as a marker value rather than silently dropping them
        result[fullKey] = undefined;
      } else {
        flattenObject(nested, fullKey, result);
      }
    } else {
      // Arrays, Dates, RegExps, Maps, Sets, and all primitives land here as-is
      result[fullKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<CronField, FieldRange> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function expandRange(start: number, end: number, step = 1): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function assertInRange(
  value: number,
  range: FieldRange,
  context: string
): void {
  if (value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} out of valid range [${range.min}-${range.max}] in "${context}"`
    );
  }
}

function parseSegment(expr: string, range: FieldRange): number[] {
  const { min, max } = range;

  // Wildcard
  if (expr === "*") {
    return expandRange(min, max);
  }

  // Step: */n, start/n, start-end/n
  if (expr.includes("/")) {
    const slashIdx = expr.indexOf("/");
    const left = expr.slice(0, slashIdx);
    const stepStr = expr.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepStr}" in "${expr}"`);
    }

    let start: number;
    let end: number;

    if (left === "*") {
      start = min;
      end = max;
    } else if (left.includes("-")) {
      const dashIdx = left.indexOf("-");
      start = parseInt(left.slice(0, dashIdx), 10);
      end = parseInt(left.slice(dashIdx + 1), 10);
      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range "${left}" in "${expr}"`);
      }
    } else {
      start = parseInt(left, 10);
      end = max;
      if (isNaN(start)) {
        throw new Error(`Invalid start value "${left}" in "${expr}"`);
      }
    }

    assertInRange(start, range, expr);
    assertInRange(end, range, expr);

    if (start > end) {
      throw new RangeError(
        `Start ${start} exceeds end ${end} in "${expr}"`
      );
    }

    return expandRange(start, end, step);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const dashIdx = expr.indexOf("-");
    const start = parseInt(expr.slice(0, dashIdx), 10);
    const end = parseInt(expr.slice(dashIdx + 1), 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range "${expr}"`);
    }

    assertInRange(start, range, expr);
    assertInRange(end, range, expr);

    if (start > end) {
      throw new RangeError(
        `Start ${start} exceeds end ${end} in "${expr}"`
      );
    }

    return expandRange(start, end);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field token "${expr}"`);
  }

  assertInRange(value, range, expr);
  return [value];
}

function parseField(expr: string, range: FieldRange): number[] {
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseSegment(part.trim(), range));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  return parseSegment(expr, range);
}

export default function parseCron(expression: string): CronExpression {
  if (!expression || typeof expression !== "string") {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  return FIELD_ORDER.reduce((acc, fieldName, i) => {
    acc[fieldName] = parseField(fields[i], FIELD_RANGES[fieldName]);
    return acc;
  }, {} as CronExpression);
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined) {
    return result;
  }

  if (typeof obj !== "object" || Array.isArray(obj)) {
    throw new TypeError(
      `Expected a plain object at root level, got: ${Array.isArray(obj) ? "array" : typeof obj}`
    );
  }

  for (const key of Object.keys(obj)) {
    // Guard against prototype pollution
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = (obj as Record<string, unknown>)[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp) &&
      !(value instanceof Map) &&
      !(value instanceof Set)
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      // Collisions: last writer wins — keys are unique by construction
      // since we traverse a tree, but guard depth against circular refs
      result[fullKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (reason: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private drainTimer: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError("refillRate must be a finite positive number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;

    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.drainTimer = null;
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed >= this.refillIntervalMs) {
      const intervals = Math.floor(elapsed / this.refillIntervalMs);
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens === 0) return true;

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.clearDrainTimer();
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError("tokens must be a finite non-negative number")
      );
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested tokens (${tokens}) exceeds maxTokens (${this.maxTokens}) — can never be satisfied`
        )
      );
    }

    // Fast path: if queue is empty, attempt immediate consumption to preserve FIFO fairness
    if (this.waitQueue.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextDrain();
    });
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0]!;
      this.lazyRefill();

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextDrain();
    } else {
      this.clearDrainTimer();
    }
  }

  private scheduleNextDrain(): void {
    // Timer already in flight — let it fire; drainQueue will reschedule if needed
    if (this.drainTimer !== null || this.waitQueue.length === 0) return;

    const delay = this.msUntilTokensAvailable(this.waitQueue[0]!.tokens);

    this.drainTimer = setTimeout(() => {
      this.drainTimer = null;
      this.drainQueue();
    }, delay);
  }

  private clearDrainTimer(): void {
    if (this.drainTimer !== null) {
      clearTimeout(this.drainTimer);
      this.drainTimer = null;
    }
  }

  private msUntilTokensAvailable(tokens: number): number {
    this.lazyRefill();

    if (this.currentTokens >= tokens) return 0;

    const deficit = tokens - this.currentTokens;
    const intervalsNeeded = Math.ceil(deficit / this.refillRate);

    // Time remaining until the next interval boundary
    const elapsedInCurrentInterval = Date.now() - this.lastRefillTime;
    const msUntilNextInterval = this.refillIntervalMs - (elapsedInCurrentInterval % this.refillIntervalMs);

    // One msUntilNextInterval covers the first interval; remainder are full intervals
    return msUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs;
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;       // inclusive upper bound for input validation
  readonly expandMax: number; // upper bound when expanding wildcards/steps
}

const FIELD_NAMES: readonly CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const FIELD_CONFIG: Readonly<Record<CronField, FieldConfig>> = {
  minute:     { min: 0, max: 59, expandMax: 59 },
  hour:       { min: 0, max: 23, expandMax: 23 },
  dayOfMonth: { min: 1, max: 31, expandMax: 31 },
  month:      { min: 1, max: 12, expandMax: 12 },
  dayOfWeek:  { min: 0, max: 7,  expandMax: 6  }, // 7 is accepted as Sunday alias
};

function toInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new SyntaxError(`Expected a non-negative integer, got "${raw}" (${context})`);
  }
  return parseInt(raw, 10);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `${context}: value ${value} is outside valid range [${min}, ${max}]`
    );
  }
}

function buildSequence(start: number, end: number, step: number): number[] {
  if (step < 1) throw new RangeError(`Step must be >= 1, got ${step}`);
  const out: number[] = [];
  for (let v = start; v <= end; v += step) out.push(v);
  return out;
}

function parseAtom(token: string, field: CronField): number[] {
  const { min, max, expandMax } = FIELD_CONFIG[field];

  // Step: */n  |  start/n  |  start-end/n
  if (token.includes("/")) {
    const slashPos = token.indexOf("/");
    const base = token.slice(0, slashPos);
    const stepRaw = token.slice(slashPos + 1);

    if (!stepRaw) {
      throw new SyntaxError(`Missing step value in "${token}" for field "${field}"`);
    }
    const step = toInt(stepRaw, `step in "${token}" for "${field}"`);
    if (step < 1) {
      throw new RangeError(`Step must be >= 1 in "${token}" for field "${field}"`);
    }

    let start: number;
    let rangeEnd: number;

    if (base === "*") {
      start = min;
      rangeEnd = expandMax;
    } else if (base.includes("-")) {
      const dashPos = base.indexOf("-");
      start = toInt(base.slice(0, dashPos), `range start in "${token}"`);
      rangeEnd = toInt(base.slice(dashPos + 1), `range end in "${token}"`);
      assertInRange(start, min, max, `field "${field}"`);
      assertInRange(rangeEnd, min, max, `field "${field}"`);
      if (start > rangeEnd) {
        throw new RangeError(
          `Range start ${start} exceeds end ${rangeEnd} in "${token}" for field "${field}"`
        );
      }
    } else {
      start = toInt(base, `start in "${token}" for "${field}"`);
      assertInRange(start, min, max, `field "${field}"`);
      rangeEnd = expandMax;
    }

    return buildSequence(start, rangeEnd, step);
  }

  // Wildcard
  if (token === "*") {
    return buildSequence(min, expandMax, 1);
  }

  // Range: a-b
  if (token.includes("-")) {
    const dashPos = token.indexOf("-");
    const start = toInt(token.slice(0, dashPos), `range start for "${field}"`);
    const end = toInt(token.slice(dashPos + 1), `range end for "${field}"`);
    assertInRange(start, min, max, `field "${field}"`);
    assertInRange(end, min, max, `field "${field}"`);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} for field "${field}"`
      );
    }
    return buildSequence(start, end, 1);
  }

  // Single value
  const value = toInt(token, `value for field "${field}"`);
  assertInRange(value, min, max, `field "${field}"`);
  return [value];
}

function parseFieldExpression(expr: string, field: CronField): number[] {
  const parts = expr.split(",");
  if (parts.some((p) => p.trim() === "")) {
    throw new SyntaxError(
      `Empty segment in field "${field}" expression: "${expr}"`
    );
  }

  const seen = new Set<number>();
  for (const part of parts) {
    for (let v of parseAtom(part.trim(), field)) {
      // Normalize dayOfWeek 7 (Sunday alias) -> 0
      if (field === "dayOfWeek" && v === 7) v = 0;
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `Cron expression must be a string, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError("Cron expression cannot be empty");
  }

  const tokens = trimmed.split(/\s+/);
  if (tokens.length !== 5) {
    throw new SyntaxError(
      `Expected exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
        `got ${tokens.length} in: "${expression}"`
    );
  }

  const result = {} as CronExpression;
  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const field = FIELD_NAMES[i];
    result[field] = parseFieldExpression(tokens[i], field);
  }
  return result;
}

type Primitive = string | number | boolean | null | undefined;
type FlatValue = Primitive | unknown[];

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, FlatValue> = {}
): Record<string, FlatValue> {
  for (const [key, value] of Object.entries(obj)) {
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      const nested = value as Record<string, unknown>;
      if (Object.keys(nested).length === 0) {
        // Preserve empty objects as leaf values
        result[flatKey] = value as FlatValue;
      } else {
        flattenObject(nested, flatKey, result);
      }
    } else {
      // Primitives, null, undefined, and arrays are leaf values
      result[flatKey] = value as FlatValue;
    }
  }

  return result;
}

export default flattenObject;

type NestedObject = Record<string, unknown>;
type FlattenedObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  // Accept both ordinary objects and null-prototype objects (Object.create(null))
  return proto === Object.prototype || proto === null;
}

function flattenInto(
  obj: NestedObject,
  prefix: string,
  seen: Set<object>,
  result: FlattenedObject
): void {
  // Guard against circular references — track the current traversal path
  if (seen.has(obj)) {
    if (prefix) result[prefix] = "[Circular]";
    return;
  }
  seen.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Empty object: preserve as a leaf so callers can detect its presence
    if (prefix) result[prefix] = obj;
    seen.delete(obj);
    return;
  }

  for (const key of keys) {
    const value = obj[key];
    const path = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      // Recurse only into plain objects — arrays, Dates, Maps, etc. are leaves
      flattenInto(value, path, seen, result);
    } else {
      result[path] = value;
    }
  }

  // Remove on the way back up so sibling branches can still detect cycles
  seen.delete(obj);
}

function flattenObject(obj: NestedObject): FlattenedObject {
  if (!isPlainObject(obj)) return {};
  const result: FlattenedObject = {};
  flattenInto(obj, "", new Set<object>(), result);
  return result;
}

export default flattenObject;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      // Advance by consumed intervals only — preserves the partial-interval remainder
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    this.refill();
    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
      );
    }

    while (true) {
      this.refill();

      if (this.tokens >= tokens) {
        this.tokens -= tokens;
        return;
      }

      // Calculate precise wait: how many full refill intervals are needed,
      // minus the partial interval already in progress.
      const deficit = tokens - this.tokens;
      const batchesNeeded = Math.ceil(deficit / this.refillRate);
      const msUntilNextRefill = this.lastRefillTime + this.refillIntervalMs - Date.now();
      const waitMs = Math.max(0, (batchesNeeded - 1) * this.refillIntervalMs + msUntilNextRefill);

      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${options.maxTokens}`);
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got ${options.refillRate}`);
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a non-negative finite number, got ${tokens}`);
    }
    if (tokens > this.maxTokens) {
      return false;
    }

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(new RangeError(`tokens must be a non-negative finite number, got ${tokens}`));
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); will never be satisfiable`)
      );
    }

    return new Promise<void>((resolve, reject) => {
      const attempt = () => {
        try {
          if (this.tryConsume(tokens)) {
            resolve();
            return;
          }

          this.lazyRefill();
          const deficit = tokens - this.currentTokens;
          const intervalsNeeded = Math.ceil(deficit / this.refillRate);
          const delayMs = Math.max(1, intervalsNeeded * this.refillIntervalMs);

          setTimeout(attempt, delayMs);
        } catch (err) {
          reject(err);
        }
      };

      attempt();
    });
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  seen = new WeakSet<object>()
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    return prefix ? { [prefix]: obj as Primitive } : {};
  }

  if (seen.has(obj)) {
    return prefix ? { [prefix]: "[Circular]" } : {};
  }

  seen.add(obj);

  const result: FlatObject = {};

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      Object.assign(result, flattenObject(value as NestedObject, flatKey, seen));
    } else {
      result[flatKey] = value as Primitive;
    }
  }

  seen.delete(obj);

  return result;
}

export default flattenObject;

type CronField = {
  values: number[];
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof ParsedCron, { min: number; max: number }> = {
  minute:     { min: 0, max: 59 },
  hour:       { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month:      { min: 1, max: 12 },
  dayOfWeek:  { min: 0, max: 6  },
};

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

function validateRange(value: number, min: number, max: number, fieldName: string): number {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] for field "${fieldName}"`
    );
  }
  return value;
}

function expandStep(min: number, max: number, step: number): number[] {
  const values: number[] = [];
  for (let i = min; i <= max; i += step) {
    values.push(i);
  }
  return values;
}

function expandRange(start: number, end: number): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function parseSegment(
  segment: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepPart}" in field "${fieldName}"`);
    }

    if (rangePart === "*") {
      return expandStep(min, max, step);
    }

    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = validateRange(parseInt(startStr, 10), min, max, fieldName);
      const end   = validateRange(parseInt(endStr, 10), min, max, fieldName);
      if (start > end) {
        throw new RangeError(`Range start ${start} > end ${end} in field "${fieldName}"`);
      }
      return expandStep(start, end, step);
    }

    throw new SyntaxError(`Invalid step expression "${segment}" in field "${fieldName}"`);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = validateRange(parseInt(startStr, 10), min, max, fieldName);
    const end   = validateRange(parseInt(endStr, 10), min, max, fieldName);
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in field "${fieldName}"`);
    }
    return expandRange(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  return [validateRange(value, min, max, fieldName)];
}

function parseField(
  expression: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const parts = expression.split(",");
  const valueSet = new Set<number>();

  for (const part of parts) {
    const expanded = parseSegment(part.trim(), min, max, fieldName);
    for (const v of expanded) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as Array<keyof ParsedCron>;

  return {
    minute:     parseField(minuteExpr, FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max,     "minute"),
    hour:       parseField(hourExpr,   FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max,       "hour"),
    dayOfMonth: parseField(domExpr,    FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max, "dayOfMonth"),
    month:      parseField(monthExpr,  FIELD_RANGES.month.min,      FIELD_RANGES.month.max,      "month"),
    dayOfWeek:  parseField(dowExpr,    FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max,  "dayOfWeek"),
  };
}

export default parseCron;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  name: keyof CronResult;
  min: number;
  max: number;
};

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max:  6 },
] as const;

function generateRange(start: number, end: number, step: number): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step}`);
  }
  if (start > end) {
    throw new RangeError(`Range start ${start} must not exceed end ${end}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseStrictInt(raw: string, label: string): number {
  if (raw === "" || raw !== raw.trim()) {
    throw new SyntaxError(`Invalid ${label}: "${raw}"`);
  }
  const n = parseInt(raw, 10);
  // Reject: NaN, floats ("1.5"), scientific notation ("1e5"), leading zeros ("01"), whitespace
  if (isNaN(n) || String(n) !== raw) {
    throw new SyntaxError(`Invalid ${label}: "${raw}" — must be a plain non-negative integer`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, label: string): void {
  if (value < min || value > max) {
    throw new RangeError(`${label} value ${value} is outside valid range [${min}, ${max}]`);
  }
}

/**
 * Parse one comma-free segment such as "*", "5", "1-5", "* /15", or "1-5/2".
 * All values are validated against [min, max].
 */
function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  segment = segment.trim();

  if (segment === "") {
    throw new SyntaxError(`Empty segment in field "${fieldName}"`);
  }

  // Bare wildcard: *
  if (segment === "*") {
    return generateRange(min, max, 1);
  }

  const slashIndex = segment.indexOf("/");

  if (slashIndex !== -1) {
    const base     = segment.slice(0, slashIndex);
    const stepPart = segment.slice(slashIndex + 1);
    const step     = parseStrictInt(stepPart, `step in "${fieldName}"`);
    if (step <= 0) {
      throw new RangeError(`Step must be positive in field "${fieldName}", got ${step}`);
    }

    if (base === "*") {
      // */n
      return generateRange(min, max, step);
    }

    // a-b/n
    const dashIndex = base.indexOf("-");
    if (dashIndex <= 0) {
      // dashIndex === 0 means leading dash (negative number attempt); -1 means missing
      throw new SyntaxError(`Invalid range base "${base}" in field "${fieldName}"`);
    }
    const start = parseStrictInt(base.slice(0, dashIndex), `range start in "${fieldName}"`);
    const end   = parseStrictInt(base.slice(dashIndex + 1), `range end in "${fieldName}"`);
    assertInRange(start, min, max, `Range start in "${fieldName}"`);
    assertInRange(end,   min, max, `Range end in "${fieldName}"`);
    return generateRange(start, end, step);
  }

  const dashIndex = segment.indexOf("-");

  if (dashIndex > 0) {
    // a-b range (dashIndex === 0 would be a negative number attempt)
    const start = parseStrictInt(segment.slice(0, dashIndex), `range start in "${fieldName}"`);
    const end   = parseStrictInt(segment.slice(dashIndex + 1), `range end in "${fieldName}"`);
    assertInRange(start, min, max, `Range start in "${fieldName}"`);
    assertInRange(end,   min, max, `Range end in "${fieldName}"`);
    return generateRange(start, end, 1);
  }

  // Single numeric value
  const value = parseStrictInt(segment, `value in "${fieldName}"`);
  assertInRange(value, min, max, `Value in "${fieldName}"`);
  return [value];
}

/**
 * Parse one cron field (which may be a comma-separated list of segments).
 * Returns a sorted, deduplicated array of all matching values.
 */
function parseField(raw: string, min: number, max: number, fieldName: string): number[] {
  raw = raw.trim();
  if (raw === "") {
    throw new SyntaxError(`Field "${fieldName}" is empty`);
  }

  const parts = raw.split(",");
  const seen  = new Set<number>();

  for (const part of parts) {
    for (const value of parseSegment(part, min, max, fieldName)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

/**
 * Parse a 5-field cron expression into resolved value arrays.
 *
 * Field order:  minute  hour  dayOfMonth  month  dayOfWeek
 * Valid ranges: 0-59    0-23  1-31        1-12   0-6
 *
 * Supported per-field formats:
 *   *          — every value in range
 *   n          — single integer
 *   a-b        — inclusive range
 *   *\/n        — every nth value starting at min
 *   a-b/n      — every nth value within range a-b
 *   x,y,z      — comma-separated list of any of the above
 */
export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseField(fields[i], min, max, name);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (reason: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private drainTimer: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.drainTimer = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const completedIntervals = Math.floor(elapsed / this.refillIntervalMs);

    if (completedIntervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + completedIntervals * this.refillRate,
      );
      // Advance by whole intervals only — preserves fractional progress
      this.lastRefillTime += completedIntervals * this.refillIntervalMs;
    }
  }

  private msUntilSatisfied(tokens: number): number {
    const deficit = tokens - this.currentTokens;
    if (deficit <= 0) return 0;

    const intervalsNeeded = Math.ceil(deficit / this.refillRate);
    const elapsedInCurrentInterval = Date.now() - this.lastRefillTime;
    const msUntilNextInterval = this.refillIntervalMs - elapsedInCurrentInterval;

    // First interval closes the partial gap; remaining intervals add full waits
    return msUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs;
  }

  private scheduleDrain(): void {
    if (this.drainTimer !== null || this.waitQueue.length === 0) return;

    // Clamp to at least 1 ms to avoid degenerate zero-delay tight loops
    const waitMs = Math.max(1, this.msUntilSatisfied(this.waitQueue[0].tokens));

    const timer = setTimeout(() => {
      this.drainTimer = null;
      this.drainWaiters();
    }, waitMs);

    // Prevent the timer from keeping the process alive in Node.js / Bun
    if (typeof timer === "object" && timer !== null && typeof (timer as { unref?: () => void }).unref === "function") {
      (timer as { unref: () => void }).unref();
    }

    this.drainTimer = timer;
  }

  private drainWaiters(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        // Head of queue is blocked; nothing behind it can proceed (FIFO fairness)
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleDrain();
    }
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) return false;
    if (tokens === 0) return true;
    // Tokens exceeding bucket capacity can never be satisfied
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    if (this.waitQueue.length > 0) {
      if (this.drainTimer !== null) {
        clearTimeout(this.drainTimer);
        this.drainTimer = null;
      }
      this.drainWaiters();
    }
  }

  async waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a non-negative finite number, got ${tokens}`);
    }
    if (tokens === 0) return;
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens} — can never be satisfied`,
      );
    }

    // Fast path: tokens available right now
    if (this.tryConsume(tokens)) return;

    // Slow path: enqueue and wait for a drain cycle
    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      if (this.drainTimer === null) {
        this.scheduleDrain();
      }
    });
  }
}

export default RateLimiter;

type FlatObject = Record<string, unknown>;

const isTraversable = (value: unknown): value is Record<string, unknown> => {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value) as unknown;
  // Only plain objects and arrays — reject Date, RegExp, Map, Set, etc.
  return (
    proto === Object.prototype ||
    proto === Array.prototype ||
    proto === null
  );
};

function _flatten(
  node: Record<string, unknown>,
  prefix: string,
  output: FlatObject,
  seen: WeakSet<object>,
): void {
  // Circular reference guard
  if (seen.has(node)) {
    if (prefix !== "") output[prefix] = "[Circular]";
    return;
  }

  const keys = Object.keys(node);

  // Preserve empty objects / arrays as leaf values rather than silently dropping them
  if (keys.length === 0) {
    if (prefix !== "") output[prefix] = node;
    return;
  }

  seen.add(node);

  for (const key of keys) {
    const value = node[key];
    const path = prefix === "" ? key : `${prefix}.${key}`;
    const child = value as Record<string, unknown>;

    if (isTraversable(value) && Object.keys(child).length > 0) {
      _flatten(child, path, output, seen);
    } else {
      output[path] = value;
    }
  }

  // Remove after fully visiting so the same object reference at a different
  // path (shared, non-circular) is still traversed correctly
  seen.delete(node);
}

export default function flattenObject(obj: Record<string, unknown>): FlatObject {
  if (obj === null || typeof obj !== "object") {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${obj === null ? "null" : typeof obj}`,
    );
  }

  const output: FlatObject = {};
  _flatten(obj, "", output, new WeakSet());
  return output;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface PendingRequest {
  tokens: number;
  resolve: () => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly pendingQueue: PendingRequest[];
  private isScheduled: boolean;

  constructor({ maxTokens, refillRate, refillIntervalMs }: RateLimiterOptions) {
    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError("refillRate must be a positive finite number");
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.pendingQueue = [];
    this.isScheduled = false;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed < 0) {
      // Guard against clock skew — reset reference point without refilling
      this.lastRefillTime = now;
      return;
    }

    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervalsElapsed * this.refillRate,
      );
      // Advance lastRefillTime by whole intervals only, preserving sub-interval remainder
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("tokens must be a positive finite number");
    }

    // A request exceeding capacity can never succeed
    if (tokens > this.maxTokens) return false;

    this.refill();

    // Respect queued waiters — bypassing the queue would starve them
    if (this.pendingQueue.length > 0 || this.currentTokens < tokens) {
      return false;
    }

    this.currentTokens -= tokens;
    return true;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Immediately satisfy any queued waiters with the restored tokens
    this.drainQueue();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("tokens must be a positive finite number");
    }

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}) and can never be satisfied`,
        ),
      );
    }

    this.refill();

    // Fast path: no contention, tokens available right now
    if (this.pendingQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.pendingQueue.push({ tokens, resolve });
      this.scheduleQueueProcessing();
    });
  }

  private drainQueue(): void {
    // FIFO: only advance while the head of the queue can be satisfied
    while (this.pendingQueue.length > 0) {
      const next = this.pendingQueue[0];
      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.pendingQueue.shift();
        next.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleQueueProcessing(): void {
    if (this.isScheduled || this.pendingQueue.length === 0) return;

    const next = this.pendingQueue[0];

    // Tokens might already be available (e.g. after reset() or a resolved waiter freed space)
    if (this.currentTokens >= next.tokens) {
      this.drainQueue();
      if (this.pendingQueue.length > 0) {
        this.scheduleQueueProcessing();
      }
      return;
    }

    // Calculate the earliest moment enough tokens will be present.
    // Each refill interval adds `refillRate` tokens. We need `intervalsNeeded` intervals.
    // The first interval fires `timeUntilNextRefill` ms from now; subsequent ones follow
    // at regular `refillIntervalMs` cadence.
    const tokensNeeded = next.tokens - this.currentTokens;
    const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
    const elapsed = Date.now() - this.lastRefillTime;
    const timeUntilNextRefill = Math.max(0, this.refillIntervalMs - elapsed);
    const delay = timeUntilNextRefill + (intervalsNeeded - 1) * this.refillIntervalMs;

    this.isScheduled = true;

    setTimeout(() => {
      this.isScheduled = false;
      this.refill();
      this.drainQueue();

      if (this.pendingQueue.length > 0) {
        // Re-schedule for the next head of queue if the bucket still isn't full enough
        this.scheduleQueueProcessing();
      }
    }, Math.max(0, delay));
  }
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInto(
  node: PlainObject | unknown[],
  prefix: string,
  result: PlainObject,
  ancestors: WeakSet<object>
): void {
  // Circular reference guard: track current ancestor chain, not all visited nodes.
  // This allows the same object to appear in sibling branches without false positives.
  if (ancestors.has(node as object)) {
    result[prefix] = "[Circular]";
    return;
  }

  ancestors.add(node as object);

  const entries: [string, unknown][] = Array.isArray(node)
    ? node.map((v, i) => [String(i), v])
    : Object.keys(node).map((k) => [k, (node as PlainObject)[k]]);

  for (const [key, value] of entries) {
    const path = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      // Only recurse into non-empty plain objects.
      // Dates, Maps, Sets, class instances, etc. fall through as leaf values.
      flattenInto(value, path, result, ancestors);
    } else if (Array.isArray(value) && value.length > 0) {
      // Recurse into non-empty arrays with numeric string keys (e.g. "a.0.b").
      flattenInto(value, path, result, ancestors);
    } else {
      // Leaf: primitives, null, undefined, empty objects, empty arrays,
      // and any non-plain object (Date, RegExp, Map, Set, …).
      result[path] = value;
    }
  }

  // Remove from ancestor set so the same reference in a sibling branch
  // is not misidentified as circular.
  ancestors.delete(node as object);
}

function flattenObject(obj: PlainObject): PlainObject {
  if (!isPlainObject(obj)) return {};
  const result: PlainObject = {};
  flattenInto(obj, "", result, new WeakSet());
  return result;
}

export default flattenObject;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_CONFIG: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function parseSegment(segment: string, min: number, max: number): number[] {
  // Wildcard: *
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Step on wildcard: */n
  if (/^\*\/\d+$/.test(segment)) {
    const step = parseInt(segment.slice(2), 10);
    if (step <= 0) {
      throw new RangeError(`Step must be a positive integer: "${segment}"`);
    }
    const values: number[] = [];
    for (let i = min; i <= max; i += step) values.push(i);
    return values;
  }

  // Range with optional step: a-b or a-b/n
  if (/^\d+-\d+(\/\d+)?$/.test(segment)) {
    const slashIdx = segment.indexOf("/");
    const step = slashIdx !== -1 ? parseInt(segment.slice(slashIdx + 1), 10) : 1;
    const rangePart = slashIdx !== -1 ? segment.slice(0, slashIdx) : segment;
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (step <= 0) {
      throw new RangeError(`Step must be a positive integer: "${segment}"`);
    }
    if (start > end) {
      throw new RangeError(`Range start exceeds end: "${segment}"`);
    }
    if (start < min || end > max) {
      throw new RangeError(
        `Range "${segment}" is outside valid bounds [${min}-${max}]`
      );
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Single number
  if (/^\d+$/.test(segment)) {
    const num = parseInt(segment, 10);
    if (num < min || num > max) {
      throw new RangeError(
        `Value ${num} is outside valid bounds [${min}-${max}]`
      );
    }
    return [num];
  }

  throw new SyntaxError(`Unrecognised cron segment: "${segment}"`);
}

function parseField(field: string, min: number, max: number): number[] {
  const seen = new Set<number>();

  for (const segment of field.split(",")) {
    for (const value of parseSegment(segment.trim(), min, max)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields; got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    const { min, max } = FIELD_CONFIG[name];
    result[name] = parseField(fields[i], min, max);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  visited = new WeakSet<object>()
): FlatObject {
  if (obj === null || typeof obj !== "object") {
    return prefix ? { [prefix]: obj as Primitive } : {};
  }

  if (visited.has(obj)) {
    return prefix ? { [prefix]: "[Circular]" } : {};
  }

  visited.add(obj);

  const result: FlatObject = {};

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      const nested = flattenObject(value as NestedObject, flatKey, visited);
      Object.assign(result, nested);
    } else {
      result[flatKey] = value as Primitive | unknown[];
    }
  }

  visited.delete(obj);

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both = Sunday
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, field: CronField): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] for field "${field}"`
    );
  }
}

function expandWildcard(min: number, max: number): number[] {
  const values: number[] = [];
  for (let i = min; i <= max; i++) values.push(i);
  return values;
}

function parseStep(expr: string, min: number, max: number, field: CronField): number[] {
  const [baseExpr, stepStr, ...extra] = expr.split("/");
  if (extra.length > 0) {
    throw new SyntaxError(`Invalid step expression "${expr}" in field "${field}"`);
  }

  const step = Number(stepStr);
  if (!Number.isInteger(step) || step < 1) {
    throw new RangeError(
      `Step value "${stepStr}" must be a positive integer in field "${field}"`
    );
  }

  let rangeMin: number;
  let rangeMax: number;

  if (baseExpr === "*") {
    rangeMin = min;
    rangeMax = max;
  } else if (baseExpr.includes("-")) {
    [rangeMin, rangeMax] = parseRangeBounds(baseExpr, min, max, field);
  } else {
    const start = Number(baseExpr);
    if (!Number.isInteger(start)) {
      throw new SyntaxError(`Invalid step base "${baseExpr}" in field "${field}"`);
    }
    assertInRange(start, min, max, field);
    rangeMin = start;
    rangeMax = max;
  }

  const values: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) values.push(i);
  return values;
}

function parseRangeBounds(
  expr: string,
  min: number,
  max: number,
  field: CronField
): [number, number] {
  const parts = expr.split("-");
  if (parts.length !== 2) {
    throw new SyntaxError(`Invalid range expression "${expr}" in field "${field}"`);
  }
  const lo = Number(parts[0]);
  const hi = Number(parts[1]);
  if (!Number.isInteger(lo) || !Number.isInteger(hi)) {
    throw new SyntaxError(`Non-integer range bounds in "${expr}" for field "${field}"`);
  }
  assertInRange(lo, min, max, field);
  assertInRange(hi, min, max, field);
  if (lo > hi) {
    throw new RangeError(
      `Range start ${lo} exceeds range end ${hi} in field "${field}"`
    );
  }
  return [lo, hi];
}

function parseRange(expr: string, min: number, max: number, field: CronField): number[] {
  const [lo, hi] = parseRangeBounds(expr, min, max, field);
  const values: number[] = [];
  for (let i = lo; i <= hi; i++) values.push(i);
  return values;
}

function parseAtom(
  expr: string,
  min: number,
  max: number,
  field: CronField
): number[] {
  if (expr === "") {
    throw new SyntaxError(`Empty expression segment in field "${field}"`);
  }

  if (expr.includes("/")) {
    return parseStep(expr, min, max, field);
  }

  if (expr === "*") {
    return expandWildcard(min, max);
  }

  if (expr.includes("-")) {
    return parseRange(expr, min, max, field);
  }

  const num = Number(expr);
  if (!Number.isInteger(num) || String(num) !== expr.trim()) {
    throw new SyntaxError(`Invalid token "${expr}" in field "${field}"`);
  }
  assertInRange(num, min, max, field);
  return [num];
}

function parseField(raw: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (raw === "" || raw === undefined) {
    throw new SyntaxError(`Missing value for field "${field}"`);
  }

  const segments = raw.split(",");
  if (segments.some((s) => s === "")) {
    throw new SyntaxError(`Empty segment in comma list for field "${field}"`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    const expanded = parseAtom(segment.trim(), min, max, field);
    for (const v of expanded) valueSet.add(v);
  }

  // Normalize dayOfWeek: treat 7 as equivalent to 0 (Sunday)
  if (field === "dayOfWeek" && valueSet.has(7)) {
    valueSet.delete(7);
    valueSet.add(0);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Collapse multiple whitespace characters between fields
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(fields[i], fieldName);
  }

  return result;
}

export default parseCron;

export type CronField = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldName = keyof CronField;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function buildRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseNonNegativeInteger(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(
      `parseCron: expected non-negative integer for ${context}, got "${raw}"`
    );
  }
  const n = Number(raw);
  if (!Number.isFinite(n)) {
    throw new Error(`parseCron: value "${raw}" overflows for ${context}`);
  }
  return n;
}

function parseToken(
  token: string,
  field: FieldName,
  min: number,
  max: number
): number[] {
  // Wildcard — full range
  if (token === "*") {
    return buildRange(min, max);
  }

  // Step: */N  — only wildcard-based steps are supported
  if (token.startsWith("*/")) {
    const stepStr = token.slice(2);
    if (stepStr === "") {
      throw new Error(`parseCron: missing step value in ${field} field`);
    }
    const step = parseNonNegativeInteger(stepStr, `step in ${field}`);
    if (step === 0) {
      throw new Error(`parseCron: step must be > 0 in ${field} field`);
    }
    const values: number[] = [];
    for (let v = min; v <= max; v += step) values.push(v);
    return values;
  }

  // Reject anything else starting with '*' (e.g. "*5", "*-3")
  if (token.startsWith("*")) {
    throw new Error(
      `parseCron: unexpected token "${token}" in ${field} field`
    );
  }

  // Range: A-B
  if (token.includes("-")) {
    const dashIdx = token.indexOf("-");
    if (token.lastIndexOf("-") !== dashIdx) {
      throw new Error(
        `parseCron: malformed range "${token}" in ${field} field`
      );
    }
    const startStr = token.slice(0, dashIdx);
    const endStr   = token.slice(dashIdx + 1);
    if (startStr === "" || endStr === "") {
      throw new Error(
        `parseCron: malformed range "${token}" in ${field} field`
      );
    }
    const lo = parseNonNegativeInteger(startStr, `range start in ${field}`);
    const hi = parseNonNegativeInteger(endStr,   `range end in ${field}`);
    if (lo < min || lo > max) {
      throw new Error(
        `parseCron: range start ${lo} out of [${min}, ${max}] for ${field}`
      );
    }
    if (hi < min || hi > max) {
      throw new Error(
        `parseCron: range end ${hi} out of [${min}, ${max}] for ${field}`
      );
    }
    if (lo > hi) {
      throw new Error(
        `parseCron: range start ${lo} > end ${hi} in ${field} field`
      );
    }
    return buildRange(lo, hi);
  }

  // Single number
  const n = parseNonNegativeInteger(token, field);
  if (n < min || n > max) {
    throw new Error(
      `parseCron: value ${n} out of [${min}, ${max}] for ${field}`
    );
  }
  return [n];
}

function parseField(raw: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (raw.includes(",")) {
    const parts = raw.split(",");
    for (const part of parts) {
      if (part === "") {
        throw new Error(
          `parseCron: empty element in ${field} list "${raw}"`
        );
      }
    }
    const seen = new Set<number>();
    for (const part of parts) {
      for (const v of parseToken(part, field, min, max)) seen.add(v);
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseToken(raw, field, min, max);
}

export default function parseCron(expression: string): CronField {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron: expected a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("parseCron: expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `parseCron: expected 5 fields, got ${parts.length} in "${expression}"`
    );
  }

  return {
    minute:     parseField(parts[0], "minute"),
    hour:       parseField(parts[1], "hour"),
    dayOfMonth: parseField(parts[2], "dayOfMonth"),
    month:      parseField(parts[3], "month"),
    dayOfWeek:  parseField(parts[4], "dayOfWeek"),
  };
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] in expression "${context}"`
    );
  }
}

function range(start: number, end: number, step = 1): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n  or  start-end/n  or  start/n
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const stepStr = segment.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in "${segment}"`);
    }

    const rangePart = segment.slice(0, slashIdx);

    if (rangePart === "*") {
      return range(min, max, step);
    }

    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);

      if (isNaN(start) || isNaN(end)) {
        throw new SyntaxError(`Invalid range "${rangePart}" in "${segment}"`);
      }

      assertInRange(start, min, max, segment);
      assertInRange(end, min, max, segment);

      if (start > end) {
        throw new RangeError(`Range start ${start} > end ${end} in "${segment}"`);
      }

      return range(start, end, step);
    }

    const start = parseInt(rangePart, 10);
    if (isNaN(start)) {
      throw new SyntaxError(`Invalid step expression "${segment}"`);
    }

    assertInRange(start, min, max, segment);
    return range(start, max, step);
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}"`);
    }

    assertInRange(start, min, max, segment);
    assertInRange(end, min, max, segment);

    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in "${segment}"`);
    }

    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}"`);
  }

  assertInRange(value, min, max, segment);
  return [value];
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list — split and parse each segment individually
  if (field.includes(",")) {
    const seen = new Set<number>();
    for (const segment of field.split(",")) {
      const trimmed = segment.trim();
      if (!trimmed) {
        throw new SyntaxError(`Empty segment in comma list "${field}"`);
      }
      for (const v of parseSegment(trimmed, min, max)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(field, min, max);
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = parts;

  return {
    minute:     parseField(minuteRaw, FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max),
    hour:       parseField(hourRaw,   FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max),
    dayOfMonth: parseField(domRaw,    FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max),
    month:      parseField(monthRaw,  FIELD_RANGES.month.min,      FIELD_RANGES.month.max),
    dayOfWeek:  parseField(dowRaw,    FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max),
  };
}

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new Error("maxTokens must be positive");
    if (options.refillRate <= 0) throw new Error("refillRate must be positive");
    if (options.refillIntervalMs <= 0) throw new Error("refillIntervalMs must be positive");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new Error("tokens must be positive");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new Error("tokens must be positive");
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new Error(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface QueueEntry {
  tokens: number;
  resolve: () => void;
  reject: (error: Error) => void;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly queue: QueueEntry[] = [];
  private scheduledTimer: ReturnType<typeof setTimeout> | null = null;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new Error("maxTokens must be positive");
    if (options.refillRate <= 0) throw new Error("refillRate must be positive");
    if (options.refillIntervalMs <= 0) throw new Error("refillIntervalMs must be positive");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  private processQueue(): void {
    while (this.queue.length > 0) {
      const entry = this.queue[0];
      if (this.currentTokens >= entry.tokens) {
        this.currentTokens -= entry.tokens;
        this.queue.shift();
        entry.resolve();
      } else {
        break;
      }
    }

    if (this.queue.length > 0) {
      this.scheduleNextProcess();
    }
  }

  private scheduleNextProcess(): void {
    if (this.scheduledTimer !== null) return;

    const entry = this.queue[0];
    const tokensNeeded = entry.tokens - this.currentTokens;
    const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
    const elapsed = Date.now() - this.lastRefillTime;
    const timeUntilNextInterval = this.refillIntervalMs - (elapsed % this.refillIntervalMs);
    const waitMs = Math.max(1, (intervalsNeeded - 1) * this.refillIntervalMs + timeUntilNextInterval);

    this.scheduledTimer = setTimeout(() => {
      this.scheduledTimer = null;
      this.refill();
      this.processQueue();
    }, waitMs);
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new Error("tokens must be positive");
    this.refill();
    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    if (this.scheduledTimer !== null) {
      clearTimeout(this.scheduledTimer);
      this.scheduledTimer = null;
    }

    this.processQueue();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new Error("tokens must be positive");
    if (tokens > this.maxTokens) {
      throw new Error(
        `Requested ${tokens} tokens exceeds maximum bucket capacity of ${this.maxTokens}`
      );
    }

    this.refill();

    if (this.queue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return;
    }

    return new Promise<void>((resolve, reject) => {
      this.queue.push({ tokens, resolve, reject });
      if (this.scheduledTimer === null) {
        this.scheduleNextProcess();
      }
    });
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] | unknown };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  visited = new WeakSet<object>()
): Record<string, unknown> {
  const result: Record<string, unknown> = {};

  if (visited.has(obj)) return result;
  visited.add(obj);

  for (const [key, value] of Object.entries(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      Object.assign(
        result,
        flattenObject(value as NestedObject, fullKey, visited)
      );
    } else {
      result[fullKey] = value;
    }
  }

  return result;
}

export default flattenObject;

type FlatValue = string | number | boolean | null | undefined | symbol | bigint | unknown[];

type FlattenedObject = Record<string, FlatValue>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flatten(
  obj: Record<string, unknown>,
  prefix: string,
  seen: WeakSet<object>,
  result: FlattenedObject
): void {
  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected${prefix ? ` at key "${prefix}"` : ""}`
    );
  }

  seen.add(obj);

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const childKeys = Object.keys(value);
      if (childKeys.length === 0) {
        // Preserve empty objects as leaf values rather than silently dropping keys
        (result as Record<string, unknown>)[flatKey] = value;
      } else {
        flatten(value, flatKey, seen, result);
      }
    } else {
      (result as Record<string, unknown>)[flatKey] = value;
    }
  }

  // Backtrack so shared references (DAGs) aren't misidentified as cycles
  seen.delete(obj);
}

function flattenObject(obj: Record<string, unknown>): FlattenedObject {
  if (!isPlainObject(obj)) {
    throw new TypeError("Input must be a plain object");
  }

  const result: FlattenedObject = {};
  flatten(obj, "", new WeakSet(), result);
  return result;
}

export default flattenObject;

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: { maxTokens: number; refillRate: number; refillIntervalMs: number }) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be positive");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be positive");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be positive");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be positive");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be positive"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens capacity"));

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const msToWait = Math.max(1, intervalsNeeded * this.refillIntervalMs - (Date.now() - this.lastRefillTime));

        setTimeout(attempt, msToWait);
      };

      attempt();
    });
  }
}

export default RateLimiter;
